// Localized long-form content for one tutorial. Generated from validated
// per-locale translation JSONs; en renders from the Markdown source.
export const entry: Partial<Record<string, LocalizedTutorialContent>> = {
  "zh": {
    title: "面向团队的 Open Design —— 可版本化的技能、专属品牌系统与反套路护栏",
    summary: "如何把 Open Design 当成团队真正可版本化的设计工作流来用 —— 构建你自己的技能与品牌 DESIGN.md，依靠反套路评审闸门，并对生产环境的使用保持务实预期。基于 AICodeKing 的分析。",
    bodyHtml: "<p>本指南讲的是把 Open Design 当成一套<strong>真正可版本化的设计工作流</strong>来用 —— 而不仅仅是一次性的原型生成器。让它对团队真正有价值的组合是：你现有的 agent、基于文件的技能，以及品牌 <code>DESIGN.md</code> 体系，再配上反套路护栏，让产出看起来不像机器生成的。本文沿用 <strong>AICodeKing</strong> 在<a href=\"https://www.youtube.com/watch?v=w2_ZwhzB1g4\">他的视频</a>里给出的分析，并结合当前版本重写、更新。完整拆解请看上方视频，或继续往下读文字版。</p>\n<p><img src=\"/tutorials/open-design-open-source-claude-alternative-aicodeking/plugin-library.webp\" alt=\"Open Design 的插件库，包含可安装的技能。\">\n<em>插件库：直接从注册表安装技能——包括反粗制滥造（anti-slop）的设计技能。</em></p>\n<h2 id=\"what-is-open-design\">什么是 Open Design？</h2>\n<p>Open Design 是一款本地优先、开源的设计应用，它连接你已经在用的编码 agent。它不自带模型，而是从你的环境路径中检测 Claude Code、Codex、Cursor、Gemini、OpenCode 和 Qwen Code 等工具，并把该 agent 当作设计引擎使用 —— 如果一个都没装，则回退到 Anthropic API（BYOK）。它采用 Apache-2.0 许可，唯一的成本就是你所选模型的开销。用 AICodeKing 的话说，它是“一层包裹在你已有 agent 外面的设计外壳”。</p>\n<h2 id=\"why-its-a-team-workflow-not-just-a-chat-box\">为什么它是团队工作流，而不只是一个聊天框</h2>\n<p>AICodeKing 看好它的原因：它不是一个带预览的空白提示框。它的价值在于<strong>三样东西的组合，而这三样都是可版本化的</strong>：</p>\n<ol>\n<li><strong>你现有的编码 agent</strong> —— 引擎，你已经付过钱了。</li>\n<li><strong>基于文件的技能</strong> —— 每个技能都为某一类具体界面（SaaS 落地页、仪表盘、定价页、文档、博客、移动应用、幻灯片）给 agent 提供规则，而不是“给我做个好看的页面”。</li>\n<li><strong><code>DESIGN.md</code> 品牌系统</strong> —— 纯 markdown 的设计系统，涵盖配色、排版、间距、布局、组件、动效、语气、品牌规则与反模式。</li>\n</ol>\n<p>因为技能和设计系统都是文件，团队可以<strong>创建自己内部的仪表盘技能和自己的品牌 <code>DESIGN.md</code>，把它们提交到 git，让 Claude Code、Codex 或任何 agent 生成遵循这些规则的成果物。</strong>这是一套可版本化、可 fork、可评审的设计工作流 —— 是一个封闭的设计聊天框给不了的。</p>\n<p><img src=\"/tutorials/open-design-open-source-claude-alternative-aicodeking/plugins-hub.webp\" alt=\"Open Design 的插件中心。\">\n<em>插件中心：浏览注册表、导入插件，并为你的团队做好准备。</em></p>\n<h2 id=\"the-anti-slop-machinery\">反套路机制</h2>\n<p>这是 AICodeKing 最喜欢的部分，也是团队产出能保持拿得出手的原因：Open Design 专门对抗 AI 生成 UI 的那些破绽。提示词栈在生成成果物之前会跑一遍<strong>多维度评审</strong>（设计哲学、层次、执行、具体性、克制），每个技能都可以附带一份 agent 必须满足的 <strong>P0/P1/P2 清单</strong>，而且仓库明确禁止那些常见的翻车套路 —— 刺眼的紫色渐变、千篇一律的 emoji 图标、随意加左边框点缀的圆角卡片、假数据、装饰性填充。再搭配<strong>需求发现表单</strong>（在动笔前先询问界面类型、受众、语气、品牌、规模）和<strong>方向选择器</strong>（带确定性调色板的精选视觉方向），agent 就有了稳定的事实来源，而不会在每次细化时漂移走样。</p>\n<h2 id=\"install\">安装</h2>\n<pre class=\"astro-code open-design-editorial\" style=\"background-color:#f7f1de;color:#15140f; overflow-x: auto;\" tabindex=\"0\" data-language=\"bash\"><code><span class=\"line\"><span style=\"color:#15140F;font-weight:bold\">git</span><span style=\"color:#6E7448\"> clone</span><span style=\"color:#6E7448\"> https://github.com/nexu-io/open-design.git</span></span>\n<span class=\"line\"><span style=\"color:#15140F;font-weight:bold\">cd</span><span style=\"color:#6E7448\"> open-design</span></span>\n<span class=\"line\"><span style=\"color:#15140F;font-weight:bold\">corepack</span><span style=\"color:#6E7448\"> enable</span><span style=\"color:#5A5448\"> &#x26;&#x26;</span><span style=\"color:#15140F;font-weight:bold\"> pnpm</span><span style=\"color:#6E7448\"> install</span></span>\n<span class=\"line\"><span style=\"color:#15140F;font-weight:bold\">pnpm</span><span style=\"color:#6E7448\"> tools-dev</span><span style=\"color:#6E7448\"> run</span><span style=\"color:#6E7448\"> web</span></span></code></pre>\n<p>打开它打印出来的本地 URL（端口是动态的 —— 不要写死）。不想折腾安装？到 <a href=\"https://open-design.ai/download\">open-design.ai/download</a> 下载<strong>桌面应用</strong>。首次加载时它会检测你已安装的 agent CLI；选一个，或使用 Anthropic BYOK 选项。完整插件库可在 <a href=\"https://open-design.ai/plugins/\">open-design.ai/plugins</a> 浏览。</p>\n<h2 id=\"a-team-flavoured-demo\">一个带团队味道的示范</h2>\n<p>AICodeKing 建议的流程能干净地映射到真实工作中：选 <strong>Codex 或 Claude Code</strong> 作为 agent，选一个<strong>技能</strong>（SaaS 落地页或仪表盘），再选一个<strong>设计系统</strong>（比如 Linear 或 Stripe —— 容易判断好坏）。提一个具体的需求，比如给一个内部产品做落地页，填好需求发现表单，选一个方向，然后让它跑。计划会流式生成出来，agent 会读取技能和 <code>DESIGN.md</code>，并写出真实的文件。</p>\n<p><img src=\"/tutorials/open-design-open-source-claude-alternative-aicodeking/motion-gallery.webp\" alt=\"Open Design 中的 HyperFrames 动效与视频画廊。\">\n<em>HyperFrames 画廊：由代码驱动的动效与视频作品，你可以复刻并二次创作。</em></p>\n<p>产出会在沙箱预览中渲染，并可导出为 HTML、PDF、ZIP 和 Markdown（幻灯片类技能为 PPTX 风格）。由于设计系统和技能始终留在提示词栈里，细化时不会漂移 —— agent 会保持稳定的参照，而不是每一轮都重新发明外观。</p>\n<h2 id=\"be-honest-about-production\">对生产环境要诚实</h2>\n<p>AICodeKing 看得很清醒，你也该如此：这是一个早期项目，所以请把它当作一个强力的<strong>起点</strong>，而不是一个即插即用的生产级设计团队。产出质量在很大程度上取决于你指向的模型 —— 弱模型加上好的设计系统，得到的依然是糟糕的设计判断力。Claude Code 能拿到最丰富的流式输出；其他 CLI 是按行缓冲的。而且由于守护进程会带着一个工作目录来启动 agent，你要慎重考虑安装哪些技能、暴露哪些目录。对于快速原型、落地页、内部仪表盘和幻灯片，它确实很有用；而对于要上线的生产 UI，先生成，然后审查代码、测试响应式、再细化。</p>\n<h2 id=\"tips\">小贴士</h2>\n<ul>\n<li><strong>写你自己的技能 + 品牌 <code>DESIGN.md</code></strong> 并提交它们 —— 这才是团队的超能力。</li>\n<li>评估产出时，<strong>选一个辨识度高的设计系统</strong>（Linear/Stripe），这样质量好坏一目了然。</li>\n<li><strong>用好需求发现表单和方向选择器</strong>，在生成前锁定方向。</li>\n<li><strong>使用本地 CLI</strong>，让生成走在你已经付费的订阅上。</li>\n<li>对生产环境而言，<strong>把产出当作起点</strong> —— 审查、测试、细化。</li>\n</ul>\n<h2 id=\"faq\">常见问题</h2>\n<p><strong>团队能构建自己的技能和设计系统吗？</strong>\n能 —— 技能是文件夹，设计系统是 <code>DESIGN.md</code> 文件。把它们提交到 git，任何已连接的 agent 都会据此生成，于是整套工作流都是可版本化、可 fork 的。</p>\n<p><strong>是什么让产出看起来不像 AI 生成的？</strong>\n生成前的多维度自我评审、每个技能各自的 P0/P1/P2 清单，以及对常见套路（紫色渐变、千篇一律的图标、假数据）的明确禁令，再加上需求发现表单和方向选择器。</p>\n<p><strong>它能用于生产环境吗？</strong>\n它是一个早期但有能力的起点。把它用于原型、仪表盘、落地页和幻灯片；对于生产 UI，请审查并细化生成的代码。</p>\n<p><strong>它免费吗？</strong>\n这款应用基于 Apache-2.0 开源，本地运行免费。你只需为所连接的 agent 与密钥的模型用量付费。</p>\n<hr>\n<p><em>这篇文字指南基于 AICodeKing 的分析。请观看上方完整视频，并<a href=\"https://www.youtube.com/watch?v=w2_ZwhzB1g4\">订阅 AICodeKing</a> 获取更多 AI 工具深度内容。</em></p>",
  },
  "ja": {
    title: "チーム向け Open Design —— バージョン管理できるスキル、自社のブランドシステム、そしてアンチスロップのガードレール",
    summary: "Open Design を、チームのための本物のバージョン管理可能なデザインワークフローとして使う方法 —— 自分たちのスキルとブランドの DESIGN.md を作り、アンチスロップの批評ゲートを活用し、本番利用については現実的な期待を保つ。AICodeKing の分析に基づく。",
    bodyHtml: "<p>このガイドは、Open Design を単なる使い捨てのプロトタイプ生成器ではなく、<strong>本物のバージョン管理可能なデザインワークフロー</strong>として使うことについてのものです。チームにとってこれを面白いものにする組み合わせはこうです——すでに使っているエージェント、ファイルベースのスキル、そしてブランドの <code>DESIGN.md</code> システム、さらに出力が「生成されたもの」に見えないよう抑えるアンチスロップのガードレール。本記事は <strong>AICodeKing</strong> が<a href=\"https://www.youtube.com/watch?v=w2_ZwhzB1g4\">彼の動画</a>で示した分析を踏まえ、現行リリースに合わせて書き直し・更新したものです。全体の解説は上の動画をご覧いただくか、文章版は以下からお読みください。</p>\n<p><img src=\"/tutorials/open-design-open-source-claude-alternative-aicodeking/plugin-library.webp\" alt=\"Open Design のプラグインライブラリ。インストール可能なスキルを備えています。\">\n<em>プラグインライブラリ：レジストリから直接スキルをインストールできます——anti-slop なデザインスキルも含みます。</em></p>\n<h2 id=\"what-is-open-design\">Open Design とは？</h2>\n<p>Open Design は、ローカルファーストでオープンソースのデザインアプリで、あなたがすでに使っているコーディングエージェントに接続します。独自のモデルを同梱するのではなく、Claude Code、Codex、Cursor、Gemini、OpenCode、Qwen Code などのツールをパスから検出し、そのエージェントをデザインエンジンとして使います——どれもインストールされていなければ、Anthropic API（BYOK）にフォールバックします。ライセンスは Apache-2.0 で、コストは選んだモデルの分だけです。AICodeKing の言葉を借りれば、これは「すでに持っているエージェントを包むデザインの殻」です。</p>\n<h2 id=\"why-its-a-team-workflow-not-just-a-chat-box\">なぜ単なるチャットボックスではなく、チームのワークフローなのか</h2>\n<p>AICodeKing が高く評価する理由はこうです——これはプレビュー付きの空白のプロンプトボックスではありません。価値は<strong>すべてバージョン管理できる三つのものの組み合わせ</strong>にあります：</p>\n<ol>\n<li><strong>あなたの既存のコーディングエージェント</strong> —— エンジン、すでに支払い済み。</li>\n<li><strong>ファイルベースのスキル</strong> —— 各スキルが、特定の面（SaaS のランディング、ダッシュボード、料金ページ、ドキュメント、ブログ、モバイルアプリ、デッキ）についてエージェントにルールを与えます。「いい感じのページを作って」ではなく。</li>\n<li><strong><code>DESIGN.md</code> ブランドシステム</strong> —— 配色、タイポグラフィ、余白、レイアウト、コンポーネント、モーション、トーン、ブランドルール、アンチパターンを網羅した、プレーンな markdown のデザインシステム。</li>\n</ol>\n<p>スキルとデザインシステムがファイルなので、チームは<strong>自社内部のダッシュボードスキルと自社ブランドの <code>DESIGN.md</code> を作り、それらを git にコミットし、Claude Code、Codex、あるいは任意のエージェントにそれらのルールに従った成果物を生成させることができます。</strong>これはバージョン管理でき、フォークでき、レビューできるデザインワークフローです——閉じたデザインチャットボックスには提供できないものです。</p>\n<p><img src=\"/tutorials/open-design-open-source-claude-alternative-aicodeking/plugins-hub.webp\" alt=\"Open Design のプラグインハブ。\">\n<em>プラグインハブ：レジストリを閲覧し、プラグインをインポートして、チーム向けに準備します。</em></p>\n<h2 id=\"the-anti-slop-machinery\">アンチスロップの仕組み</h2>\n<p>AICodeKing のお気に入りの部分であり、チームの出力が見せられる水準を保てる理由でもあります：Open Design は AI 生成 UI の「ばれる兆候」と戦います。プロンプトスタックは、成果物を出す前に<strong>多次元の批評</strong>（デザイン哲学、階層、実行、具体性、抑制）を走らせ、各スキルはエージェントが満たすべき <strong>P0/P1/P2 のチェックリスト</strong>を同梱でき、リポジトリはよくある失敗パターンを明示的に禁じています——けばけばしい紫のグラデーション、ありふれた絵文字アイコン、左ボーダーのアクセントが付いた適当な角丸カード、偽の数値、装飾的な穴埋め。さらに<strong>ディスカバリーフォーム</strong>（書き始める前に面、対象、トーン、ブランド、規模を尋ねる）と<strong>方向性ピッカー</strong>（決定論的なパレットを備えた厳選されたビジュアルの方向性）と組み合わせることで、エージェントは細部を詰めるたびに漂流するのではなく、安定した信頼できる情報源を持ちます。</p>\n<h2 id=\"install\">インストール</h2>\n<pre class=\"astro-code open-design-editorial\" style=\"background-color:#f7f1de;color:#15140f; overflow-x: auto;\" tabindex=\"0\" data-language=\"bash\"><code><span class=\"line\"><span style=\"color:#15140F;font-weight:bold\">git</span><span style=\"color:#6E7448\"> clone</span><span style=\"color:#6E7448\"> https://github.com/nexu-io/open-design.git</span></span>\n<span class=\"line\"><span style=\"color:#15140F;font-weight:bold\">cd</span><span style=\"color:#6E7448\"> open-design</span></span>\n<span class=\"line\"><span style=\"color:#15140F;font-weight:bold\">corepack</span><span style=\"color:#6E7448\"> enable</span><span style=\"color:#5A5448\"> &#x26;&#x26;</span><span style=\"color:#15140F;font-weight:bold\"> pnpm</span><span style=\"color:#6E7448\"> install</span></span>\n<span class=\"line\"><span style=\"color:#15140F;font-weight:bold\">pnpm</span><span style=\"color:#6E7448\"> tools-dev</span><span style=\"color:#6E7448\"> run</span><span style=\"color:#6E7448\"> web</span></span></code></pre>\n<p>表示されるローカル URL を開きます（ポートは動的です——ハードコードしないこと）。セットアップなしがいいですか？<strong>デスクトップアプリ</strong>を <a href=\"https://open-design.ai/download\">open-design.ai/download</a> から入手してください。初回起動時に、インストール済みのエージェント CLI を検出します。どれか一つを選ぶか、Anthropic BYOK オプションを使ってください。プラグインライブラリの全体は <a href=\"https://open-design.ai/plugins/\">open-design.ai/plugins</a> で閲覧できます。</p>\n<h2 id=\"a-team-flavoured-demo\">チームらしさのあるデモ</h2>\n<p>AICodeKing が提案するフローは、実際の仕事にきれいに対応します：エージェントとして <strong>Codex か Claude Code</strong> を選び、<strong>スキル</strong>（SaaS ランディングまたはダッシュボード）を選び、<strong>デザインシステム</strong>（例えば Linear や Stripe——良し悪しを判断しやすい）を選びます。社内向けプロダクトのランディングページのような具体的なものをプロンプトに与え、ディスカバリーフォームを埋め、方向性を選び、走らせます。計画がストリーミングで流れ込み、エージェントがスキルと <code>DESIGN.md</code> を読み、実際のファイルを書きます。</p>\n<p><img src=\"/tutorials/open-design-open-source-claude-alternative-aicodeking/motion-gallery.webp\" alt=\"Open Design の HyperFrames モーション・動画ギャラリー。\">\n<em>HyperFrames ギャラリー：コード駆動のモーションや動画作品を、フォークしてリミックスできます。</em></p>\n<p>出力はサンドボックス化されたプレビューでレンダリングされ、HTML、PDF、ZIP、Markdown（デッキ系スキルでは PPTX 形式）にエクスポートできます。デザインシステムとスキルがプロンプトスタックに留まり続けるため、詰めの作業で漂流しません——エージェントは毎ターン見た目を発明し直すのではなく、安定した参照を保ちます。</p>\n<h2 id=\"be-honest-about-production\">本番利用について正直であろう</h2>\n<p>AICodeKing は冷静に見ていますし、あなたもそうあるべきです：これは初期段階のプロジェクトなので、即戦力の本番デザインチームではなく、強力な<strong>出発点</strong>として扱ってください。出力の品質は、向ける先のモデルに大きく依存します——弱いモデルに良いデザインシステムを足しても、デザインの判断力は弱いままです。Claude Code は最も豊富なストリーミングを得られます。ほかの CLI は行単位でバッファされます。そしてデーモンは作業ディレクトリを伴ってエージェントを起動するため、どのスキルをインストールし、どのディレクトリを露出させるかは慎重に考えてください。手早いプロトタイプ、ランディングページ、社内ダッシュボード、デッキには本当に役立ちます。出荷する本番 UI については、生成してから、コードをレビューし、レスポンシブをテストし、詰めてください。</p>\n<h2 id=\"tips\">ヒント</h2>\n<ul>\n<li><strong>自分のスキル + ブランド <code>DESIGN.md</code> を書いて</strong>コミットしましょう——それがチームの超能力です。</li>\n<li>出力を判断するときは<strong>認識しやすいデザインシステム</strong>（Linear/Stripe）を選び、品質を評価しやすくしましょう。</li>\n<li><strong>ディスカバリーフォームと方向性ピッカーを活用して</strong>、生成前に方向性を固めましょう。</li>\n<li><strong>ローカルの CLI を使って</strong>、生成をすでに支払っているサブスクリプションに乗せましょう。</li>\n<li>本番に向けては<strong>出力を出発点として扱い</strong>——レビューし、テストし、詰めましょう。</li>\n</ul>\n<h2 id=\"faq\">よくある質問</h2>\n<p><strong>チームは自分たちのスキルとデザインシステムを作れますか？</strong>\nはい——スキルはフォルダ、デザインシステムは <code>DESIGN.md</code> ファイルです。git にコミットすれば、接続された任意のエージェントがそれらに対して生成するので、ワークフロー全体がバージョン管理可能でフォーク可能になります。</p>\n<p><strong>出力が AI 生成に見えないようにしているものは何ですか？</strong>\n出力前の多次元の自己批評、スキルごとの P0/P1/P2 チェックリスト、よくあるスロップのパターン（紫のグラデーション、ありふれたアイコン、偽の数値）の明示的な禁止、それにディスカバリーフォームと方向性ピッカーです。</p>\n<p><strong>本番で使える状態ですか？</strong>\n初期段階ながら能力のある出発点です。プロトタイプ、ダッシュボード、ランディングページ、デッキに使ってください。本番 UI については、生成されたコードをレビューして詰めてください。</p>\n<p><strong>無料ですか？</strong>\nアプリは Apache-2.0 のもとでオープンソースであり、ローカルで無料に動かせます。支払うのは、接続したエージェントとキーのモデル利用分だけです。</p>\n<hr>\n<p><em>この文章ガイドは AICodeKing の分析に基づいています。上の完全な動画をご覧いただき、より多くの AI ツール深掘りのために<a href=\"https://www.youtube.com/watch?v=w2_ZwhzB1g4\">AICodeKing を購読してください</a>。</em></p>",
  },
  "ko": {
    title: "팀을 위한 Open Design — 버전 관리되는 스킬, 나만의 브랜드 시스템, 그리고 안티슬롭 가드레일",
    summary: "Open Design을 팀을 위한 진짜 버전 관리 가능한 디자인 워크플로로 사용하는 방법 — 자신만의 스킬과 브랜드 DESIGN.md를 만들고, 안티슬롭 비평 게이트에 기대며, 프로덕션 사용에 대해서는 현실적인 기대를 유지하기. AICodeKing의 분석에 기반함.",
    bodyHtml: "<p>이 가이드는 Open Design을 일회성 프로토타입 생성기가 아니라 <strong>진짜 버전 관리 가능한 디자인 워크플로</strong>로 사용하는 것에 관한 것입니다. 팀에게 이것을 흥미롭게 만드는 조합은 이렇습니다: 이미 쓰고 있는 에이전트, 파일 기반 스킬, 그리고 브랜드 <code>DESIGN.md</code> 시스템에, 결과물이 생성된 것처럼 보이지 않게 막아 주는 안티슬롭 가드레일까지. 이 글은 <strong>AICodeKing</strong>이 <a href=\"https://www.youtube.com/watch?v=w2_ZwhzB1g4\">자신의 영상</a>에서 제시한 분석을 따르되, 현재 릴리스에 맞춰 다시 쓰고 갱신한 것입니다. 전체 해설은 위 영상을 보거나, 글 버전은 아래에서 이어 읽으세요.</p>\n<p><img src=\"/tutorials/open-design-open-source-claude-alternative-aicodeking/plugin-library.webp\" alt=\"설치 가능한 스킬이 포함된 Open Design 플러그인 라이브러리.\">\n<em>플러그인 라이브러리: 레지스트리에서 곧바로 스킬을 설치하세요 — anti-slop 디자인 스킬도 포함됩니다.</em></p>\n<h2 id=\"what-is-open-design\">Open Design이란?</h2>\n<p>Open Design은 로컬 우선이자 오픈소스인 디자인 앱으로, 이미 사용 중인 코딩 에이전트에 연결됩니다. 자체 모델을 탑재하는 대신, Claude Code, Codex, Cursor, Gemini, OpenCode, Qwen Code 같은 도구를 경로에서 감지해 그 에이전트를 디자인 엔진으로 사용합니다 — 아무것도 설치돼 있지 않으면 Anthropic API(BYOK)로 폴백합니다. 라이선스는 Apache-2.0이며, 유일한 비용은 선택한 모델의 사용료뿐입니다. AICodeKing의 표현을 빌리면, 이것은 “이미 가지고 있는 에이전트를 감싸는 디자인 껍데기”입니다.</p>\n<h2 id=\"why-its-a-team-workflow-not-just-a-chat-box\">왜 단순한 채팅 박스가 아니라 팀 워크플로인가</h2>\n<p>AICodeKing이 높이 평가하는 이유: 이것은 미리보기가 달린 빈 프롬프트 박스가 아닙니다. 가치는 <strong>모두 버전 관리 가능한 세 가지의 조합</strong>에 있습니다:</p>\n<ol>\n<li><strong>이미 쓰고 있는 코딩 에이전트</strong> — 엔진이며, 이미 비용을 지불했습니다.</li>\n<li><strong>파일 기반 스킬</strong> — 각 스킬은 “멋진 페이지 하나 만들어 줘”가 아니라, 특정 표면(SaaS 랜딩, 대시보드, 가격 페이지, 문서, 블로그, 모바일 앱, 덱)에 대한 규칙을 에이전트에 제공합니다.</li>\n<li><strong><code>DESIGN.md</code> 브랜드 시스템</strong> — 색상, 타이포그래피, 간격, 레이아웃, 컴포넌트, 모션, 톤, 브랜드 규칙, 안티패턴을 아우르는 순수 markdown 디자인 시스템.</li>\n</ol>\n<p>스킬과 디자인 시스템이 파일이기 때문에, 팀은 <strong>자체 내부 대시보드 스킬과 자체 브랜드 <code>DESIGN.md</code>를 만들고, 그것들을 git에 커밋하며, Claude Code, Codex 또는 어떤 에이전트든 그 규칙을 따르는 산출물을 생성하게 할 수 있습니다.</strong> 이는 버전 관리되고, 포크할 수 있고, 리뷰할 수 있는 디자인 워크플로입니다 — 닫혀 있는 디자인 채팅 박스가 제공할 수 없는 것이죠.</p>\n<p><img src=\"/tutorials/open-design-open-source-claude-alternative-aicodeking/plugins-hub.webp\" alt=\"Open Design 플러그인 허브.\">\n<em>플러그인 허브: 레지스트리를 둘러보고, 플러그인을 가져오고, 팀을 위해 준비하세요.</em></p>\n<h2 id=\"the-anti-slop-machinery\">안티슬롭 장치</h2>\n<p>AICodeKing이 가장 좋아하는 부분이자, 팀 산출물이 내놓을 만한 수준을 유지하는 이유입니다: Open Design은 AI 생성 UI의 티 나는 흔적과 싸웁니다. 프롬프트 스택은 산출물을 내보내기 전에 <strong>다차원 비평</strong>(디자인 철학, 위계, 실행, 구체성, 절제)을 돌리고, 각 스킬은 에이전트가 반드시 만족시켜야 하는 <strong>P0/P1/P2 체크리스트</strong>를 함께 담을 수 있으며, 저장소는 흔한 실패 패턴을 명시적으로 금지합니다 — 과한 보라색 그라데이션, 흔해 빠진 이모지 아이콘, 좌측 보더 강조가 붙은 아무 둥근 카드, 가짜 지표, 장식용 채움. <strong>디스커버리 폼</strong>(작성 전에 표면, 대상, 톤, 브랜드, 규모를 묻는다)과 <strong>방향 선택기</strong>(결정론적 팔레트를 갖춘 엄선된 시각적 방향)와 짝지어, 에이전트는 매번 다듬을 때마다 표류하는 대신 안정적인 진실의 출처를 갖게 됩니다.</p>\n<h2 id=\"install\">설치</h2>\n<pre class=\"astro-code open-design-editorial\" style=\"background-color:#f7f1de;color:#15140f; overflow-x: auto;\" tabindex=\"0\" data-language=\"bash\"><code><span class=\"line\"><span style=\"color:#15140F;font-weight:bold\">git</span><span style=\"color:#6E7448\"> clone</span><span style=\"color:#6E7448\"> https://github.com/nexu-io/open-design.git</span></span>\n<span class=\"line\"><span style=\"color:#15140F;font-weight:bold\">cd</span><span style=\"color:#6E7448\"> open-design</span></span>\n<span class=\"line\"><span style=\"color:#15140F;font-weight:bold\">corepack</span><span style=\"color:#6E7448\"> enable</span><span style=\"color:#5A5448\"> &#x26;&#x26;</span><span style=\"color:#15140F;font-weight:bold\"> pnpm</span><span style=\"color:#6E7448\"> install</span></span>\n<span class=\"line\"><span style=\"color:#15140F;font-weight:bold\">pnpm</span><span style=\"color:#6E7448\"> tools-dev</span><span style=\"color:#6E7448\"> run</span><span style=\"color:#6E7448\"> web</span></span></code></pre>\n<p>출력되는 로컬 URL을 여세요(포트는 동적입니다 — 하드코딩하지 마세요). 설정 없이 쓰고 싶나요? <a href=\"https://open-design.ai/download\">open-design.ai/download</a>에서 <strong>데스크톱 앱</strong>을 받으세요. 처음 로드할 때 설치된 에이전트 CLI를 감지합니다. 하나를 고르거나 Anthropic BYOK 옵션을 사용하세요. 전체 플러그인 라이브러리는 <a href=\"https://open-design.ai/plugins/\">open-design.ai/plugins</a>에서 둘러볼 수 있습니다.</p>\n<h2 id=\"a-team-flavoured-demo\">팀 색채가 담긴 데모</h2>\n<p>AICodeKing이 제안하는 흐름은 실제 업무에 깔끔하게 대응됩니다: 에이전트로 <strong>Codex나 Claude Code</strong>를 고르고, <strong>스킬</strong>(SaaS 랜딩 또는 대시보드)을 고르고, <strong>디자인 시스템</strong>(예: Linear 또는 Stripe — 판단하기 쉽다)을 고르세요. 사내 제품을 위한 랜딩 페이지처럼 구체적인 것을 프롬프트로 주고, 디스커버리 폼을 채우고, 방향을 고른 뒤 돌리세요. 계획이 스트리밍으로 흘러 들어오고, 에이전트가 스킬과 <code>DESIGN.md</code>를 읽으며 실제 파일을 작성합니다.</p>\n<p><img src=\"/tutorials/open-design-open-source-claude-alternative-aicodeking/motion-gallery.webp\" alt=\"Open Design의 HyperFrames 모션·비디오 갤러리.\">\n<em>HyperFrames 갤러리: 코드 기반의 모션과 비디오 작품을 포크하고 리믹스할 수 있습니다.</em></p>\n<p>산출물은 샌드박스 미리보기에서 렌더링되며 HTML, PDF, ZIP, Markdown(덱 스킬은 PPTX 형식)으로 내보낼 수 있습니다. 디자인 시스템과 스킬이 프롬프트 스택에 남아 있기 때문에 다듬는 과정에서 표류하지 않습니다 — 에이전트는 매 턴마다 룩을 새로 발명하는 대신 안정적인 참조를 유지합니다.</p>\n<h2 id=\"be-honest-about-production\">프로덕션에 대해 솔직해지기</h2>\n<p>AICodeKing은 냉정하게 보고 있고, 당신도 그래야 합니다: 이것은 초기 단계의 프로젝트이므로, 바로 투입 가능한 프로덕션 디자인 팀이 아니라 강력한 <strong>출발점</strong>으로 다루세요. 산출물의 품질은 당신이 가리키는 모델에 크게 좌우됩니다 — 약한 모델에 좋은 디자인 시스템을 더해도 디자인 판단력은 여전히 약합니다. Claude Code는 가장 풍부한 스트리밍을 제공합니다. 다른 CLI는 줄 단위로 버퍼링됩니다. 그리고 데몬이 작업 디렉터리를 가지고 에이전트를 띄우므로, 어떤 스킬을 설치하고 어떤 디렉터리를 노출할지 신중하게 생각하세요. 빠른 프로토타입, 랜딩 페이지, 사내 대시보드, 덱에는 정말로 유용합니다. 출시할 프로덕션 UI에는, 먼저 생성한 뒤 코드를 리뷰하고, 반응형을 테스트하고, 다듬으세요.</p>\n<h2 id=\"tips\">팁</h2>\n<ul>\n<li><strong>자신만의 스킬 + 브랜드 <code>DESIGN.md</code>를 작성하고</strong> 커밋하세요 — 그것이 팀의 초능력입니다.</li>\n<li>산출물을 판단할 때는 <strong>알아보기 쉬운 디자인 시스템</strong>(Linear/Stripe)을 골라 품질을 평가하기 쉽게 하세요.</li>\n<li><strong>디스커버리 폼과 방향 선택기를 활용해</strong> 생성 전에 방향을 고정하세요.</li>\n<li><strong>로컬 CLI를 사용해</strong> 생성을 이미 지불 중인 구독 위에서 돌리세요.</li>\n<li>프로덕션을 위해서는 <strong>산출물을 출발점으로 다루세요</strong> — 리뷰하고, 테스트하고, 다듬으세요.</li>\n</ul>\n<h2 id=\"faq\">자주 묻는 질문</h2>\n<p><strong>팀이 자체 스킬과 디자인 시스템을 만들 수 있나요?</strong>\n네 — 스킬은 폴더이고 디자인 시스템은 <code>DESIGN.md</code> 파일입니다. git에 커밋하면 연결된 어떤 에이전트든 그것에 맞춰 생성하므로, 워크플로 전체가 버전 관리되고 포크할 수 있습니다.</p>\n<p><strong>산출물이 AI 생성처럼 보이지 않게 하는 것은 무엇인가요?</strong>\n출력 전 다차원 자기 비평, 스킬별 P0/P1/P2 체크리스트, 흔한 슬롭 패턴(보라색 그라데이션, 흔해 빠진 아이콘, 가짜 지표)에 대한 명시적 금지, 그리고 디스커버리 폼과 방향 선택기입니다.</p>\n<p><strong>프로덕션에 바로 쓸 수 있나요?</strong>\n초기 단계지만 역량 있는 출발점입니다. 프로토타입, 대시보드, 랜딩 페이지, 덱에 사용하세요. 프로덕션 UI에는 생성된 코드를 리뷰하고 다듬으세요.</p>\n<p><strong>무료인가요?</strong>\n앱은 Apache-2.0 하에 오픈소스이며 로컬에서 무료로 실행됩니다. 연결한 에이전트와 키의 모델 사용량에 대해서만 비용을 지불합니다.</p>\n<hr>\n<p><em>이 글 가이드는 AICodeKing의 분석에 기반합니다. 위의 전체 영상을 보시고, 더 많은 AI 도구 심층 분석을 위해 <a href=\"https://www.youtube.com/watch?v=w2_ZwhzB1g4\">AICodeKing을 구독하세요</a>.</em></p>",
  },
  "de": {
    title: "Open Design für Teams — versionierbare Skills, ein eigenes Brand-System und Anti-Slop-Leitplanken",
    summary: "Wie man Open Design als echten, versionierbaren Design-Workflow für ein Team nutzt — eigene Skills und eine Brand-DESIGN.md bauen, sich auf das Anti-Slop-Kritik-Gate stützen und bei der Produktionsnutzung ehrlich bleiben. Basierend auf der Analyse von AICodeKing.",
    bodyHtml: "<p>In diesem Leitfaden geht es darum, Open Design als <strong>echten, versionierbaren Design-Workflow</strong> zu nutzen — nicht bloß als einmaligen Prototyp-Generator. Die Kombination, die es für ein Team interessant macht: dein bereits genutzter Agent, dateibasierte Skills und Brand-<code>DESIGN.md</code>-Systeme, ergänzt um Anti-Slop-Leitplanken, damit das Ergebnis nicht generiert aussieht. Er folgt der Analyse, die <strong>AICodeKing</strong> in <a href=\"https://www.youtube.com/watch?v=w2_ZwhzB1g4\">seinem Video</a> gibt, neu geschrieben und auf den aktuellen Release gebracht. Schau dir das Video oben für die vollständige Erklärung an oder lies weiter für die schriftliche Fassung.</p>\n<p><img src=\"/tutorials/open-design-open-source-claude-alternative-aicodeking/plugin-library.webp\" alt=\"Die Plugin-Bibliothek von Open Design mit installierbaren Skills.\">\n<em>Die Plugin-Bibliothek: installiere Skills direkt aus der Registry – einschließlich Anti-Slop-Design-Skills.</em></p>\n<h2 id=\"what-is-open-design\">Was ist Open Design?</h2>\n<p>Open Design ist eine lokal-first, quelloffene Design-App, die sich mit dem Coding-Agenten verbindet, den du ohnehin schon nutzt. Statt ein eigenes Modell mitzuliefern, erkennt sie Tools wie Claude Code, Codex, Cursor, Gemini, OpenCode und Qwen Code anhand deines Pfads und nutzt diesen Agenten als Design-Engine — mit einem Anthropic-API-Fallback (BYOK), falls keines installiert ist. Sie steht unter Apache-2.0, und der einzige Kostenpunkt ist das Modell, das du wählst. Wie AICodeKing es formuliert, ist sie „eine Design-Hülle um die Agenten, die du bereits hast“.</p>\n<h2 id=\"why-its-a-team-workflow-not-just-a-chat-box\">Warum es ein Team-Workflow ist, nicht nur eine Chat-Box</h2>\n<p>Der Grund, warum AICodeKing es so schätzt: Es ist keine leere Prompt-Box mit Vorschau. Der Wert liegt in der <strong>Kombination dreier Dinge, die allesamt versionierbar sind</strong>:</p>\n<ol>\n<li><strong>Dein vorhandener Coding-Agent</strong> — die Engine, bereits bezahlt.</li>\n<li><strong>Dateibasierte Skills</strong> — jeder Skill gibt dem Agenten Regeln für eine bestimmte Oberfläche (SaaS-Landingpage, Dashboard, Preisseite, Doku, Blog, Mobile-App, Decks), statt „mach mir eine schöne Seite“.</li>\n<li><strong><code>DESIGN.md</code>-Brand-Systeme</strong> — reine Markdown-Designsysteme für Farbe, Typografie, Abstände, Layout, Komponenten, Motion, Tonalität, Markenregeln und Anti-Patterns.</li>\n</ol>\n<p>Da Skills und Designsysteme Dateien sind, kann ein Team <strong>seinen eigenen internen Dashboard-Skill und seine eigene Brand-<code>DESIGN.md</code> erstellen, sie ins Git committen und Claude Code, Codex oder einen beliebigen Agenten Artefakte erzeugen lassen, die diesen Regeln folgen.</strong> Das ist ein versionierter, forkbarer, reviewbarer Design-Workflow — etwas, das eine abgeschottete Design-Chat-Box nicht bieten kann.</p>\n<p><img src=\"/tutorials/open-design-open-source-claude-alternative-aicodeking/plugins-hub.webp\" alt=\"Der Plugin-Hub von Open Design.\">\n<em>Der Plugin-Hub: durchsuche die Registry, importiere Plugins und bereite sie für dein Team vor.</em></p>\n<h2 id=\"the-anti-slop-machinery\">Die Anti-Slop-Maschinerie</h2>\n<p>AICodeKings Lieblingsteil und der Grund, warum die Team-Ergebnisse vorzeigbar bleiben: Open Design bekämpft die verräterischen Merkmale KI-generierter UI. Der Prompt-Stack durchläuft eine <strong>mehrdimensionale Kritik, bevor ein Artefakt ausgegeben wird</strong> (Designphilosophie, Hierarchie, Ausführung, Spezifität, Zurückhaltung), jeder Skill kann eine <strong>P0/P1/P2-Checkliste</strong> mitliefern, die der Agent erfüllen muss, und das Repo verbietet ausdrücklich die üblichen Fehlermuster — aggressive lila Verläufe, generische Emoji-Icons, willkürliche abgerundete Karten mit Akzent am linken Rand, gefälschte Metriken, dekorativer Füllstoff. Gepaart mit dem <strong>Discovery-Formular</strong> (es fragt vor dem Schreiben nach Oberfläche, Zielgruppe, Tonalität, Marke, Umfang) und dem <strong>Richtungswähler</strong> (kuratierte visuelle Richtungen mit deterministischen Paletten) hat der Agent eine stabile Quelle der Wahrheit, statt bei jeder Verfeinerung abzudriften.</p>\n<h2 id=\"install\">Installation</h2>\n<pre class=\"astro-code open-design-editorial\" style=\"background-color:#f7f1de;color:#15140f; overflow-x: auto;\" tabindex=\"0\" data-language=\"bash\"><code><span class=\"line\"><span style=\"color:#15140F;font-weight:bold\">git</span><span style=\"color:#6E7448\"> clone</span><span style=\"color:#6E7448\"> https://github.com/nexu-io/open-design.git</span></span>\n<span class=\"line\"><span style=\"color:#15140F;font-weight:bold\">cd</span><span style=\"color:#6E7448\"> open-design</span></span>\n<span class=\"line\"><span style=\"color:#15140F;font-weight:bold\">corepack</span><span style=\"color:#6E7448\"> enable</span><span style=\"color:#5A5448\"> &#x26;&#x26;</span><span style=\"color:#15140F;font-weight:bold\"> pnpm</span><span style=\"color:#6E7448\"> install</span></span>\n<span class=\"line\"><span style=\"color:#15140F;font-weight:bold\">pnpm</span><span style=\"color:#6E7448\"> tools-dev</span><span style=\"color:#6E7448\"> run</span><span style=\"color:#6E7448\"> web</span></span></code></pre>\n<p>Öffne die ausgegebene lokale URL (ein dynamischer Port — nicht fest verdrahten). Lieber ohne Einrichtung? Hol dir die <strong>Desktop-App</strong> unter <a href=\"https://open-design.ai/download\">open-design.ai/download</a>. Beim ersten Laden erkennt sie deine installierten Agent-CLIs; wähle eine aus oder nutze die Anthropic-BYOK-Option. Durchstöbere die vollständige Plugin-Bibliothek unter <a href=\"https://open-design.ai/plugins/\">open-design.ai/plugins</a>.</p>\n<h2 id=\"a-team-flavoured-demo\">Eine Demo mit Team-Note</h2>\n<p>Der von AICodeKing vorgeschlagene Ablauf lässt sich sauber auf echte Arbeit übertragen: Wähle <strong>Codex oder Claude Code</strong> als Agent, einen <strong>Skill</strong> (SaaS-Landingpage oder Dashboard) und ein <strong>Designsystem</strong> (z. B. Linear oder Stripe — leicht zu beurteilen). Gib etwas Konkretes als Prompt vor, etwa eine Landingpage für ein internes Produkt, fülle das Discovery-Formular aus, wähle eine Richtung und lass es laufen. Der Plan streamt herein, der Agent liest den Skill und die <code>DESIGN.md</code> und schreibt echte Dateien.</p>\n<p><img src=\"/tutorials/open-design-open-source-claude-alternative-aicodeking/motion-gallery.webp\" alt=\"Die HyperFrames-Galerie für Motion und Video in Open Design.\">\n<em>Die HyperFrames-Galerie: code-getriebene Motion- und Video-Stücke, die du forken und remixen kannst.</em></p>\n<p>Die Ergebnisse werden in einer Sandbox-Vorschau gerendert und lassen sich als HTML, PDF, ZIP und Markdown exportieren (PPTX-artig bei Deck-Skills). Da Designsystem und Skill im Prompt-Stack bleiben, driften Verfeinerungen nicht ab — der Agent behält eine stabile Referenz, statt den Look in jeder Runde neu zu erfinden.</p>\n<h2 id=\"be-honest-about-production\">Sei ehrlich beim Thema Produktion</h2>\n<p>AICodeKing sieht das nüchtern, und du solltest es auch: Dies ist ein frühes Projekt, behandle es also als starken <strong>Ausgangspunkt</strong>, nicht als sofort einsetzbares Produktions-Designteam. Die Ergebnisqualität hängt stark vom Modell ab, auf das du es richtest — ein schwaches Modell plus ein gutes Designsystem ergibt immer noch schwaches Designurteil. Claude Code bekommt das reichhaltigste Streaming; andere CLIs sind zeilengepuffert. Und da der Daemon Agenten mit einem Arbeitsverzeichnis startet, überleg dir gut, welche Skills du installierst und welche Verzeichnisse du freigibst. Für schnelle Prototypen, Landingpages, interne Dashboards und Decks ist es wirklich nützlich; für ausgelieferte Produktions-UI gilt: generieren, dann den Code reviewen, Responsiveness testen und verfeinern.</p>\n<h2 id=\"tips\">Tipps</h2>\n<ul>\n<li><strong>Schreib deinen eigenen Skill + Brand-<code>DESIGN.md</code></strong> und committe sie — das ist die Superkraft des Teams.</li>\n<li><strong>Wähl ein wiedererkennbares Designsystem</strong> (Linear/Stripe), wenn du Ergebnisse beurteilst, damit die Qualität leicht einzuschätzen ist.</li>\n<li><strong>Stütze dich auf das Discovery-Formular und den Richtungswähler</strong>, um die Richtung vor der Generierung festzulegen.</li>\n<li><strong>Nutze eine lokale CLI</strong>, damit die Generierung auf einem Abo läuft, das du ohnehin bezahlst.</li>\n<li><strong>Behandle das Ergebnis als Ausgangspunkt</strong> für die Produktion — reviewen, testen, verfeinern.</li>\n</ul>\n<h2 id=\"faq\">FAQ</h2>\n<p><strong>Kann ein Team eigene Skills und Designsysteme bauen?</strong>\nJa — Skills sind Ordner und Designsysteme sind <code>DESIGN.md</code>-Dateien. Committe sie ins Git, und jeder verbundene Agent generiert dagegen, sodass der gesamte Workflow versioniert und forkbar ist.</p>\n<p><strong>Was verhindert, dass das Ergebnis KI-generiert aussieht?</strong>\nEine mehrdimensionale Selbstkritik vor der Ausgabe, skillspezifische P0/P1/P2-Checklisten und ein ausdrückliches Verbot gängiger Slop-Muster (lila Verläufe, generische Icons, gefälschte Metriken), dazu das Discovery-Formular und der Richtungswähler.</p>\n<p><strong>Ist es produktionsreif?</strong>\nEs ist ein früher, leistungsfähiger Ausgangspunkt. Nutze es für Prototypen, Dashboards, Landingpages und Decks; für Produktions-UI reviewe und verfeinere den generierten Code.</p>\n<p><strong>Ist es kostenlos?</strong>\nDie App ist quelloffen unter Apache-2.0 und lokal kostenlos lauffähig. Du zahlst nur für die Modellnutzung des jeweils verbundenen Agenten und Schlüssels.</p>\n<hr>\n<p><em>Dieser schriftliche Leitfaden basiert auf der Analyse von AICodeKing. Schau dir das vollständige Video oben an und <a href=\"https://www.youtube.com/watch?v=w2_ZwhzB1g4\">abonniere AICodeKing</a> für weitere tiefgehende Analysen zu KI-Tools.</em></p>",
  },
  "fr": {
    title: "Open Design pour les équipes — des skills versionnables, votre propre système de marque et des garde-fous anti-slop",
    summary: "Comment utiliser Open Design comme un véritable workflow de design versionnable pour une équipe — créer vos propres skills et un DESIGN.md de marque, vous appuyer sur le portail de critique anti-slop et garder des attentes honnêtes quant à l'usage en production. D'après l'analyse d'AICodeKing.",
    bodyHtml: "<p>Ce guide explique comment utiliser Open Design comme un <strong>véritable workflow de design versionnable</strong> — et pas seulement comme un générateur de prototypes ponctuel. La combinaison qui le rend intéressant pour une équipe : votre agent existant, des skills basés sur des fichiers et des systèmes de marque <code>DESIGN.md</code>, le tout assorti de garde-fous anti-slop pour empêcher le résultat d'avoir l'air généré. Il suit l'analyse qu'<strong>AICodeKing</strong> livre dans <a href=\"https://www.youtube.com/watch?v=w2_ZwhzB1g4\">sa vidéo</a>, réécrite et mise à jour pour la version actuelle. Regardez la vidéo ci-dessus pour le décryptage complet, ou poursuivez la lecture pour la version écrite.</p>\n<p><img src=\"/tutorials/open-design-open-source-claude-alternative-aicodeking/plugin-library.webp\" alt=\"La bibliothèque de plugins d'Open Design, avec des skills installables.\">\n<em>La bibliothèque de plugins : installez des skills directement depuis le registre — y compris des skills de design anti-slop.</em></p>\n<h2 id=\"what-is-open-design\">Qu'est-ce qu'Open Design ?</h2>\n<p>Open Design est une application de design local-first et open source qui se connecte à l'agent de code que vous utilisez déjà. Au lieu d'embarquer son propre modèle, elle détecte dans votre PATH des outils comme Claude Code, Codex, Cursor, Gemini, OpenCode et Qwen Code, et utilise cet agent comme moteur de design — avec un repli sur l'API Anthropic (BYOK) si aucun n'est installé. Elle est sous licence Apache-2.0, et le seul coût est celui du modèle que vous choisissez. Comme le dit AICodeKing, c'est « une coquille de design autour des agents que vous avez déjà ».</p>\n<h2 id=\"why-its-a-team-workflow-not-just-a-chat-box\">Pourquoi c'est un workflow d'équipe, pas juste une zone de chat</h2>\n<p>La raison pour laquelle AICodeKing l'apprécie : ce n'est pas une zone de prompt vide avec un aperçu. La valeur réside dans la <strong>combinaison de trois choses, toutes versionnables</strong> :</p>\n<ol>\n<li><strong>Votre agent de code existant</strong> — le moteur, déjà payé.</li>\n<li><strong>Des skills basés sur des fichiers</strong> — chaque skill donne à l'agent des règles pour une surface précise (landing SaaS, dashboard, page de tarifs, doc, blog, application mobile, présentations) au lieu de « fais-moi une belle page ».</li>\n<li><strong>Des systèmes de marque <code>DESIGN.md</code></strong> — des systèmes de design en simple markdown couvrant couleur, typographie, espacement, mise en page, composants, mouvement, ton, règles de marque et anti-patterns.</li>\n</ol>\n<p>Parce que les skills et les systèmes de design sont des fichiers, une équipe peut <strong>créer son propre skill de dashboard interne et son propre <code>DESIGN.md</code> de marque, les committer dans git, et faire en sorte que Claude Code, Codex ou n'importe quel agent génère des artefacts respectant ces règles.</strong> C'est un workflow de design versionné, forkable, revisable — quelque chose qu'une zone de chat de design verrouillée ne peut pas offrir.</p>\n<p><img src=\"/tutorials/open-design-open-source-claude-alternative-aicodeking/plugins-hub.webp\" alt=\"Le hub de plugins d'Open Design.\">\n<em>Le hub de plugins : parcourez le registre, importez des plugins et préparez-les pour votre équipe.</em></p>\n<h2 id=\"the-anti-slop-machinery\">La mécanique anti-slop</h2>\n<p>La partie préférée d'AICodeKing, et la raison pour laquelle le résultat d'équipe reste présentable : Open Design combat les signes révélateurs des UI générées par IA. La pile de prompts exécute une <strong>critique multidimensionnelle avant d'émettre un artefact</strong> (philosophie de design, hiérarchie, exécution, spécificité, retenue), chaque skill peut embarquer une <strong>checklist P0/P1/P2</strong> que l'agent doit satisfaire, et le dépôt interdit explicitement les modes d'échec habituels — dégradés violets agressifs, icônes emoji génériques, cartes arrondies au hasard avec accent en bordure gauche, métriques bidon, remplissage décoratif. Couplé au <strong>formulaire de découverte</strong> (il interroge sur la surface, l'audience, le ton, la marque, l'échelle avant d'écrire) et au <strong>sélecteur de direction</strong> (directions visuelles soignées avec palettes déterministes), l'agent dispose d'une source de vérité stable au lieu de dériver à chaque ajustement.</p>\n<h2 id=\"install\">Installation</h2>\n<pre class=\"astro-code open-design-editorial\" style=\"background-color:#f7f1de;color:#15140f; overflow-x: auto;\" tabindex=\"0\" data-language=\"bash\"><code><span class=\"line\"><span style=\"color:#15140F;font-weight:bold\">git</span><span style=\"color:#6E7448\"> clone</span><span style=\"color:#6E7448\"> https://github.com/nexu-io/open-design.git</span></span>\n<span class=\"line\"><span style=\"color:#15140F;font-weight:bold\">cd</span><span style=\"color:#6E7448\"> open-design</span></span>\n<span class=\"line\"><span style=\"color:#15140F;font-weight:bold\">corepack</span><span style=\"color:#6E7448\"> enable</span><span style=\"color:#5A5448\"> &#x26;&#x26;</span><span style=\"color:#15140F;font-weight:bold\"> pnpm</span><span style=\"color:#6E7448\"> install</span></span>\n<span class=\"line\"><span style=\"color:#15140F;font-weight:bold\">pnpm</span><span style=\"color:#6E7448\"> tools-dev</span><span style=\"color:#6E7448\"> run</span><span style=\"color:#6E7448\"> web</span></span></code></pre>\n<p>Ouvrez l'URL locale qu'elle affiche (un port dynamique — ne le codez pas en dur). Vous préférez sans installation ? Récupérez l'<strong>application de bureau</strong> sur <a href=\"https://open-design.ai/download\">open-design.ai/download</a>. Au premier chargement, elle détecte les CLI d'agent installés ; choisissez-en un, ou utilisez l'option Anthropic BYOK. Parcourez la bibliothèque complète de plugins sur <a href=\"https://open-design.ai/plugins/\">open-design.ai/plugins</a>.</p>\n<h2 id=\"a-team-flavoured-demo\">Une démo aux couleurs d'une équipe</h2>\n<p>Le flux suggéré par AICodeKing se transpose proprement au travail réel : choisissez <strong>Codex ou Claude Code</strong> comme agent, un <strong>skill</strong> (landing SaaS ou dashboard) et un <strong>système de design</strong> (par ex. Linear ou Stripe — faciles à juger). Donnez un prompt concret, comme une landing page pour un produit interne, remplissez le formulaire de découverte, choisissez une direction et laissez tourner. Le plan arrive en streaming, l'agent lit le skill et le <code>DESIGN.md</code>, et écrit de vrais fichiers.</p>\n<p><img src=\"/tutorials/open-design-open-source-claude-alternative-aicodeking/motion-gallery.webp\" alt=\"La galerie de motion et de vidéo HyperFrames dans Open Design.\">\n<em>La galerie HyperFrames : des créations de motion et de vidéo pilotées par le code, à forker et à remixer.</em></p>\n<p>Les sorties s'affichent dans un aperçu en bac à sable et s'exportent en HTML, PDF, ZIP et Markdown (façon PPTX pour les skills de présentation). Comme le système de design et le skill restent dans la pile de prompts, les ajustements ne dérivent pas — l'agent conserve une référence stable au lieu de réinventer le look à chaque tour.</p>\n<h2 id=\"be-honest-about-production\">Soyez honnête sur la production</h2>\n<p>AICodeKing a les idées claires, et vous devriez aussi : c'est un projet précoce, alors traitez-le comme un solide <strong>point de départ</strong>, pas comme une équipe de design de production clé en main. La qualité du résultat dépend fortement du modèle que vous lui pointez — un modèle faible plus un bon système de design donne quand même un jugement de design faible. Claude Code obtient le streaming le plus riche ; les autres CLI sont bufferisées par ligne. Et comme le daemon lance des agents avec un répertoire de travail, réfléchissez bien aux skills que vous installez et aux répertoires que vous exposez. Pour des prototypes rapides, des landing pages, des dashboards internes et des présentations, c'est réellement utile ; pour une UI de production livrée, générez, puis relisez le code, testez la responsivité et peaufinez.</p>\n<h2 id=\"tips\">Astuces</h2>\n<ul>\n<li><strong>Écrivez votre propre skill + <code>DESIGN.md</code> de marque</strong> et committez-les — c'est le super-pouvoir de l'équipe.</li>\n<li><strong>Choisissez un système de design reconnaissable</strong> (Linear/Stripe) pour juger le résultat, afin que la qualité soit facile à évaluer.</li>\n<li><strong>Appuyez-vous sur le formulaire de découverte et le sélecteur de direction</strong> pour verrouiller la direction avant la génération.</li>\n<li><strong>Utilisez une CLI locale</strong> pour que la génération s'appuie sur un abonnement que vous payez déjà.</li>\n<li><strong>Traitez le résultat comme un point de départ</strong> pour la production — relisez, testez, peaufinez.</li>\n</ul>\n<h2 id=\"faq\">FAQ</h2>\n<p><strong>Une équipe peut-elle créer ses propres skills et systèmes de design ?</strong>\nOui — les skills sont des dossiers et les systèmes de design sont des fichiers <code>DESIGN.md</code>. Committez-les dans git et n'importe quel agent connecté génère en s'y conformant, de sorte que tout le workflow est versionné et forkable.</p>\n<p><strong>Qu'est-ce qui empêche le résultat d'avoir l'air généré par IA ?</strong>\nUne autocritique multidimensionnelle avant émission, des checklists P0/P1/P2 par skill et une interdiction explicite des motifs de slop courants (dégradés violets, icônes génériques, métriques bidon), plus le formulaire de découverte et le sélecteur de direction.</p>\n<p><strong>Est-ce prêt pour la production ?</strong>\nC'est un point de départ précoce mais capable. Utilisez-le pour des prototypes, des dashboards, des landing pages et des présentations ; pour une UI de production, relisez et peaufinez le code généré.</p>\n<p><strong>Est-ce gratuit ?</strong>\nL'application est open source sous Apache-2.0 et gratuite à exécuter en local. Vous ne payez que l'utilisation du modèle de l'agent et de la clé que vous connectez.</p>\n<hr>\n<p><em>Ce guide écrit s'appuie sur l'analyse d'AICodeKing. Regardez la vidéo complète ci-dessus, et <a href=\"https://www.youtube.com/watch?v=w2_ZwhzB1g4\">abonnez-vous à AICodeKing</a> pour d'autres analyses approfondies d'outils d'IA.</em></p>",
  },
  "ru": {
    title: "Open Design для команд — версионируемые навыки, собственная бренд-система и анти-слоп-ограничители",
    summary: "Как использовать Open Design в качестве настоящего, версионируемого дизайн-процесса для команды — создавать собственные навыки и бренд-DESIGN.md, опираться на анти-слоп-шлюз критики и честно оценивать применимость в продакшене. По материалам разбора AICodeKing.",
    bodyHtml: "<p>Это руководство о том, как использовать Open Design как <strong>настоящий, версионируемый дизайн-процесс</strong> — а не просто разовый генератор прототипов. Сочетание, которое делает его интересным для команды: ваш уже используемый агент, файловые навыки и бренд-системы <code>DESIGN.md</code>, дополненные анти-слоп-ограничителями, чтобы результат не выглядел сгенерированным. Оно следует разбору, который <strong>AICodeKing</strong> даёт в <a href=\"https://www.youtube.com/watch?v=w2_ZwhzB1g4\">своём видео</a>, переписанному и обновлённому под текущий релиз. Посмотрите видео выше для полного разбора или читайте дальше письменную версию.</p>\n<p><img src=\"/tutorials/open-design-open-source-claude-alternative-aicodeking/plugin-library.webp\" alt=\"Библиотека плагинов Open Design с устанавливаемыми навыками.\">\n<em>Библиотека плагинов: устанавливайте навыки прямо из реестра — включая дизайн-навыки против «слопа» (anti-slop).</em></p>\n<h2 id=\"what-is-open-design\">Что такое Open Design?</h2>\n<p>Open Design — это локальное, открытое дизайн-приложение, которое подключается к агенту для кодинга, который у вас уже есть. Вместо того чтобы поставлять собственную модель, оно обнаруживает в вашем PATH такие инструменты, как Claude Code, Codex, Cursor, Gemini, OpenCode и Qwen Code, и использует этот агент как дизайн-движок — с откатом на Anthropic API (BYOK), если ни один не установлен. Оно распространяется под Apache-2.0, и единственная статья расходов — это та модель, которую вы выберете. Как говорит AICodeKing, это «дизайн-оболочка вокруг агентов, которые у вас уже есть».</p>\n<h2 id=\"why-its-a-team-workflow-not-just-a-chat-box\">Почему это командный процесс, а не просто окно чата</h2>\n<p>Причина, по которой AICodeKing его ценит: это не пустое окно для промпта с предпросмотром. Ценность — в <strong>сочетании трёх вещей, и все они версионируемы</strong>:</p>\n<ol>\n<li><strong>Ваш существующий агент для кодинга</strong> — движок, уже оплаченный.</li>\n<li><strong>Файловые навыки</strong> — каждый навык даёт агенту правила для конкретной поверхности (SaaS-лендинг, дашборд, страница тарифов, документация, блог, мобильное приложение, презентации), вместо «сделай мне красивую страницу».</li>\n<li><strong>Бренд-системы <code>DESIGN.md</code></strong> — дизайн-системы на простом markdown, охватывающие цвет, типографику, отступы, вёрстку, компоненты, движение, тон, правила бренда и антипаттерны.</li>\n</ol>\n<p>Поскольку навыки и дизайн-системы — это файлы, команда может <strong>создать собственный внутренний навык для дашбордов и собственный бренд-<code>DESIGN.md</code>, закоммитить их в git и заставить Claude Code, Codex или любой агент генерировать артефакты, следующие этим правилам.</strong> Это версионируемый, форкаемый, проверяемый дизайн-процесс — то, чего закрытое окно дизайн-чата предложить не может.</p>\n<p><img src=\"/tutorials/open-design-open-source-claude-alternative-aicodeking/plugins-hub.webp\" alt=\"Центр плагинов Open Design.\">\n<em>Центр плагинов: просматривайте реестр, импортируйте плагины и подготавливайте их для своей команды.</em></p>\n<h2 id=\"the-anti-slop-machinery\">Анти-слоп-механика</h2>\n<p>Любимая часть AICodeKing и причина, по которой результат команды остаётся презентабельным: Open Design борется с выдающими признаками UI, сгенерированного ИИ. Стек промптов прогоняет <strong>многомерную критику перед выдачей артефакта</strong> (философия дизайна, иерархия, исполнение, конкретность, сдержанность), каждый навык может поставляться с <strong>чек-листом P0/P1/P2</strong>, который агент обязан выполнить, а репозиторий явно запрещает привычные провальные паттерны — агрессивные фиолетовые градиенты, шаблонные эмодзи-иконки, случайные скруглённые карточки с акцентом по левому краю, фейковые метрики, декоративный наполнитель. В паре с <strong>формой обнаружения</strong> (она спрашивает о поверхности, аудитории, тоне, бренде, масштабе до того, как начнёт писать) и <strong>выбором направления</strong> (выверенные визуальные направления с детерминированными палитрами) агент получает стабильный источник истины вместо того, чтобы дрейфовать на каждой доработке.</p>\n<h2 id=\"install\">Установка</h2>\n<pre class=\"astro-code open-design-editorial\" style=\"background-color:#f7f1de;color:#15140f; overflow-x: auto;\" tabindex=\"0\" data-language=\"bash\"><code><span class=\"line\"><span style=\"color:#15140F;font-weight:bold\">git</span><span style=\"color:#6E7448\"> clone</span><span style=\"color:#6E7448\"> https://github.com/nexu-io/open-design.git</span></span>\n<span class=\"line\"><span style=\"color:#15140F;font-weight:bold\">cd</span><span style=\"color:#6E7448\"> open-design</span></span>\n<span class=\"line\"><span style=\"color:#15140F;font-weight:bold\">corepack</span><span style=\"color:#6E7448\"> enable</span><span style=\"color:#5A5448\"> &#x26;&#x26;</span><span style=\"color:#15140F;font-weight:bold\"> pnpm</span><span style=\"color:#6E7448\"> install</span></span>\n<span class=\"line\"><span style=\"color:#15140F;font-weight:bold\">pnpm</span><span style=\"color:#6E7448\"> tools-dev</span><span style=\"color:#6E7448\"> run</span><span style=\"color:#6E7448\"> web</span></span></code></pre>\n<p>Откройте локальный URL, который оно выведет (порт динамический — не прописывайте его жёстко). Предпочитаете без настройки? Возьмите <strong>десктоп-приложение</strong> на <a href=\"https://open-design.ai/download\">open-design.ai/download</a>. При первом запуске оно обнаруживает установленные CLI агентов; выберите один или используйте опцию Anthropic BYOK. Изучите полную библиотеку плагинов на <a href=\"https://open-design.ai/plugins/\">open-design.ai/plugins</a>.</p>\n<h2 id=\"a-team-flavoured-demo\">Демо с командным уклоном</h2>\n<p>Предложенный AICodeKing порядок чисто ложится на реальную работу: выберите в качестве агента <strong>Codex или Claude Code</strong>, выберите <strong>навык</strong> (SaaS-лендинг или дашборд) и <strong>дизайн-систему</strong> (например, Linear или Stripe — легко оценить). Задайте что-то конкретное в промпте, например лендинг для внутреннего продукта, заполните форму обнаружения, выберите направление и запустите. План приходит потоком, агент читает навык и <code>DESIGN.md</code> и пишет настоящие файлы.</p>\n<p><img src=\"/tutorials/open-design-open-source-claude-alternative-aicodeking/motion-gallery.webp\" alt=\"Галерея анимации и видео HyperFrames в Open Design.\">\n<em>Галерея HyperFrames: анимационные и видеоработы на основе кода, которые можно форкнуть и переработать.</em></p>\n<p>Результаты отрисовываются в песочном предпросмотре и экспортируются в HTML, PDF, ZIP и Markdown (в стиле PPTX для навыков-презентаций). Поскольку дизайн-система и навык остаются в стеке промптов, доработки не дрейфуют — агент держит стабильную опору вместо того, чтобы заново изобретать облик на каждом ходу.</p>\n<h2 id=\"be-honest-about-production\">Будьте честны насчёт продакшена</h2>\n<p>AICodeKing смотрит трезво, и вам стоит так же: это ранний проект, поэтому относитесь к нему как к сильной <strong>отправной точке</strong>, а не как к готовой к подключению продакшен-дизайн-команде. Качество результата сильно зависит от модели, на которую вы его направляете — слабая модель плюс хорошая дизайн-система всё равно дают слабое дизайн-суждение. Claude Code получает самый насыщенный стриминг; другие CLI буферизуются построчно. А поскольку демон запускает агентов с рабочим каталогом, продумайте, какие навыки вы устанавливаете и какие каталоги открываете. Для быстрых прототипов, лендингов, внутренних дашбордов и презентаций оно по-настоящему полезно; для продакшен-UI, который вы выпускаете, генерируйте, затем проверяйте код, тестируйте адаптивность и дорабатывайте.</p>\n<h2 id=\"tips\">Советы</h2>\n<ul>\n<li><strong>Напишите собственный навык + бренд-<code>DESIGN.md</code></strong> и закоммитьте их — это и есть командная суперсила.</li>\n<li><strong>Выбирайте узнаваемую дизайн-систему</strong> (Linear/Stripe), оценивая результат, чтобы качество было легко судить.</li>\n<li><strong>Опирайтесь на форму обнаружения и выбор направления</strong>, чтобы зафиксировать направление до генерации.</li>\n<li><strong>Используйте локальный CLI</strong>, чтобы генерация шла на подписке, за которую вы уже платите.</li>\n<li><strong>Относитесь к результату как к отправной точке</strong> для продакшена — проверяйте, тестируйте, дорабатывайте.</li>\n</ul>\n<h2 id=\"faq\">Частые вопросы</h2>\n<p><strong>Может ли команда создавать собственные навыки и дизайн-системы?</strong>\nДа — навыки это папки, а дизайн-системы это файлы <code>DESIGN.md</code>. Закоммитьте их в git, и любой подключённый агент генерирует с опорой на них, так что весь процесс становится версионируемым и форкаемым.</p>\n<p><strong>Что не даёт результату выглядеть сгенерированным ИИ?</strong>\nМногомерная самокритика перед выдачей, чек-листы P0/P1/P2 для каждого навыка и явный запрет распространённых слоп-паттернов (фиолетовые градиенты, шаблонные иконки, фейковые метрики), плюс форма обнаружения и выбор направления.</p>\n<p><strong>Готово ли оно к продакшену?</strong>\nЭто ранняя, но дееспособная отправная точка. Используйте его для прототипов, дашбордов, лендингов и презентаций; для продакшен-UI проверяйте и дорабатывайте сгенерированный код.</p>\n<p><strong>Это бесплатно?</strong>\nПриложение открыто под Apache-2.0 и бесплатно для локального запуска. Вы платите только за использование модели тем агентом и ключом, которые подключаете.</p>\n<hr>\n<p><em>Это письменное руководство основано на разборе AICodeKing. Посмотрите полное видео выше и <a href=\"https://www.youtube.com/watch?v=w2_ZwhzB1g4\">подпишитесь на AICodeKing</a> для новых глубоких разборов ИИ-инструментов.</em></p>",
  },
  "es": {
    title: "Open Design para equipos: skills versionables, tu propio sistema de marca y barreras anti-slop",
    summary: "Cómo usar Open Design como un flujo de trabajo de diseño real y versionable para un equipo: crear tus propios skills y un DESIGN.md de marca, apoyarte en la compuerta de crítica anti-slop y mantener expectativas honestas sobre el uso en producción. Basado en el análisis de AICodeKing.",
    bodyHtml: "<p>Esta guía trata de usar Open Design como un <strong>flujo de trabajo de diseño real y versionable</strong>, no solo como un generador de prototipos puntual. La combinación que lo hace interesante para un equipo: tu agente actual, skills basados en archivos y sistemas de marca <code>DESIGN.md</code>, con barreras anti-slop que evitan que el resultado parezca generado. Sigue el análisis que <strong>AICodeKing</strong> ofrece en <a href=\"https://www.youtube.com/watch?v=w2_ZwhzB1g4\">su video</a>, reescrito y actualizado para la versión actual. Mira el video de arriba para el desglose completo, o sigue leyendo para la versión escrita.</p>\n<p><img src=\"/tutorials/open-design-open-source-claude-alternative-aicodeking/plugin-library.webp\" alt=\"La biblioteca de plugins de Open Design, con skills instalables.\">\n<em>La biblioteca de plugins: instala skills directamente desde el registro, incluidos skills de diseño anti-slop.</em></p>\n<h2 id=\"what-is-open-design\">¿Qué es Open Design?</h2>\n<p>Open Design es una aplicación de diseño local-first y de código abierto que se conecta al agente de programación que ya usas. En vez de incluir su propio modelo, detecta en tu PATH herramientas como Claude Code, Codex, Cursor, Gemini, OpenCode y Qwen Code, y usa ese agente como motor de diseño, con un repliegue a la API de Anthropic (BYOK) si no hay ninguno instalado. Es Apache-2.0, y el único costo es el del modelo que elijas. Como dice AICodeKing, es «una cáscara de diseño alrededor de los agentes que ya tienes».</p>\n<h2 id=\"why-its-a-team-workflow-not-just-a-chat-box\">Por qué es un flujo de trabajo de equipo, no solo una caja de chat</h2>\n<p>La razón por la que AICodeKing lo valora: no es una caja de prompt en blanco con una vista previa. El valor está en la <strong>combinación de tres cosas, todas versionables</strong>:</p>\n<ol>\n<li><strong>Tu agente de programación actual</strong>: el motor, ya pagado.</li>\n<li><strong>Skills basados en archivos</strong>: cada skill le da al agente reglas para una superficie específica (landing SaaS, dashboard, página de precios, documentación, blog, app móvil, presentaciones) en vez de «hazme una página bonita».</li>\n<li><strong>Sistemas de marca <code>DESIGN.md</code></strong>: sistemas de diseño en markdown plano que cubren color, tipografía, espaciado, maquetación, componentes, movimiento, tono, reglas de marca y antipatrones.</li>\n</ol>\n<p>Como los skills y los sistemas de diseño son archivos, un equipo puede <strong>crear su propio skill interno de dashboard y su propio <code>DESIGN.md</code> de marca, hacerles commit en git y lograr que Claude Code, Codex o cualquier agente genere artefactos que sigan esas reglas.</strong> Eso es un flujo de trabajo de diseño versionado, forkeable y revisable, algo que una caja de chat de diseño cerrada no puede ofrecer.</p>\n<p><img src=\"/tutorials/open-design-open-source-claude-alternative-aicodeking/plugins-hub.webp\" alt=\"El centro de plugins de Open Design.\">\n<em>El centro de plugins: explora el registro, importa plugins y prepáralos para tu equipo.</em></p>\n<h2 id=\"the-anti-slop-machinery\">La maquinaria anti-slop</h2>\n<p>La parte favorita de AICodeKing, y la razón por la que el resultado del equipo se mantiene presentable: Open Design combate las señales delatoras de la UI generada por IA. La pila de prompts ejecuta una <strong>crítica multidimensional antes de emitir un artefacto</strong> (filosofía de diseño, jerarquía, ejecución, especificidad, contención), cada skill puede incluir una <strong>lista de verificación P0/P1/P2</strong> que el agente debe satisfacer, y el repositorio prohíbe explícitamente los modos de fallo habituales: degradados morados agresivos, iconos emoji genéricos, tarjetas redondeadas al azar con acento en el borde izquierdo, métricas falsas, relleno decorativo. Combinado con el <strong>formulario de descubrimiento</strong> (pregunta por superficie, audiencia, tono, marca y escala antes de escribir) y el <strong>selector de dirección</strong> (direcciones visuales curadas con paletas deterministas), el agente cuenta con una fuente de verdad estable en lugar de irse a la deriva en cada refinamiento.</p>\n<h2 id=\"install\">Instalación</h2>\n<pre class=\"astro-code open-design-editorial\" style=\"background-color:#f7f1de;color:#15140f; overflow-x: auto;\" tabindex=\"0\" data-language=\"bash\"><code><span class=\"line\"><span style=\"color:#15140F;font-weight:bold\">git</span><span style=\"color:#6E7448\"> clone</span><span style=\"color:#6E7448\"> https://github.com/nexu-io/open-design.git</span></span>\n<span class=\"line\"><span style=\"color:#15140F;font-weight:bold\">cd</span><span style=\"color:#6E7448\"> open-design</span></span>\n<span class=\"line\"><span style=\"color:#15140F;font-weight:bold\">corepack</span><span style=\"color:#6E7448\"> enable</span><span style=\"color:#5A5448\"> &#x26;&#x26;</span><span style=\"color:#15140F;font-weight:bold\"> pnpm</span><span style=\"color:#6E7448\"> install</span></span>\n<span class=\"line\"><span style=\"color:#15140F;font-weight:bold\">pnpm</span><span style=\"color:#6E7448\"> tools-dev</span><span style=\"color:#6E7448\"> run</span><span style=\"color:#6E7448\"> web</span></span></code></pre>\n<p>Abre la URL local que imprime (un puerto dinámico; no lo escribas a mano de forma fija). ¿Prefieres sin configuración? Consigue la <strong>aplicación de escritorio</strong> en <a href=\"https://open-design.ai/download\">open-design.ai/download</a>. En la primera carga detecta los CLI de agente instalados; elige uno o usa la opción Anthropic BYOK. Explora la biblioteca completa de plugins en <a href=\"https://open-design.ai/plugins/\">open-design.ai/plugins</a>.</p>\n<h2 id=\"a-team-flavoured-demo\">Una demo con sabor de equipo</h2>\n<p>El flujo que sugiere AICodeKing se traslada limpiamente al trabajo real: elige <strong>Codex o Claude Code</strong> como agente, elige un <strong>skill</strong> (landing SaaS o dashboard) y un <strong>sistema de diseño</strong> (p. ej., Linear o Stripe, fáciles de juzgar). Da un prompt concreto, como una landing page para un producto interno, completa el formulario de descubrimiento, elige una dirección y déjalo correr. El plan llega en streaming, el agente lee el skill y el <code>DESIGN.md</code>, y escribe archivos reales.</p>\n<p><img src=\"/tutorials/open-design-open-source-claude-alternative-aicodeking/motion-gallery.webp\" alt=\"La galería de motion y vídeo HyperFrames en Open Design.\">\n<em>La galería HyperFrames: piezas de motion y vídeo impulsadas por código que puedes forkear y remezclar.</em></p>\n<p>Las salidas se renderizan en una vista previa en sandbox y se exportan a HTML, PDF, ZIP y Markdown (estilo PPTX para los skills de presentaciones). Como el sistema de diseño y el skill permanecen en la pila de prompts, los refinamientos no se desvían: el agente conserva una referencia estable en vez de reinventar el aspecto en cada turno.</p>\n<h2 id=\"be-honest-about-production\">Sé honesto sobre la producción</h2>\n<p>AICodeKing lo ve con claridad, y tú también deberías: este es un proyecto temprano, así que trátalo como un <strong>punto de partida</strong> sólido, no como un equipo de diseño de producción listo para enchufar. La calidad del resultado depende mucho del modelo al que lo apuntes: un modelo débil más un buen sistema de diseño sigue dando un criterio de diseño débil. Claude Code obtiene el streaming más rico; los demás CLI van en búfer por líneas. Y como el daemon lanza agentes con un directorio de trabajo, piensa bien qué skills instalas y qué directorios expones. Para prototipos rápidos, landing pages, dashboards internos y presentaciones es realmente útil; para una UI de producción que se publica, genera y luego revisa el código, prueba la responsividad y refínalo.</p>\n<h2 id=\"tips\">Consejos</h2>\n<ul>\n<li><strong>Escribe tu propio skill + <code>DESIGN.md</code> de marca</strong> y hazles commit: ese es el superpoder del equipo.</li>\n<li><strong>Elige un sistema de diseño reconocible</strong> (Linear/Stripe) al juzgar el resultado, para que la calidad sea fácil de evaluar.</li>\n<li><strong>Apóyate en el formulario de descubrimiento y el selector de dirección</strong> para fijar la dirección antes de generar.</li>\n<li><strong>Usa un CLI local</strong> para que la generación se apoye en una suscripción que ya pagas.</li>\n<li><strong>Trata el resultado como un punto de partida</strong> para producción: revisa, prueba, refina.</li>\n</ul>\n<h2 id=\"faq\">Preguntas frecuentes</h2>\n<p><strong>¿Puede un equipo crear sus propios skills y sistemas de diseño?</strong>\nSí: los skills son carpetas y los sistemas de diseño son archivos <code>DESIGN.md</code>. Hazles commit en git y cualquier agente conectado genera contra ellos, así que todo el flujo de trabajo queda versionado y forkeable.</p>\n<p><strong>¿Qué evita que el resultado parezca generado por IA?</strong>\nUna autocrítica multidimensional antes de emitir, listas de verificación P0/P1/P2 por skill y una prohibición explícita de los patrones de slop comunes (degradados morados, iconos genéricos, métricas falsas), además del formulario de descubrimiento y el selector de dirección.</p>\n<p><strong>¿Está listo para producción?</strong>\nEs un punto de partida temprano pero capaz. Úsalo para prototipos, dashboards, landing pages y presentaciones; para UI de producción, revisa y refina el código generado.</p>\n<p><strong>¿Es gratis?</strong>\nLa aplicación es de código abierto bajo Apache-2.0 y gratuita para ejecutar en local. Solo pagas el uso del modelo del agente y la clave que conectes.</p>\n<hr>\n<p><em>Esta guía escrita se basa en el análisis de AICodeKing. Mira el video completo de arriba y <a href=\"https://www.youtube.com/watch?v=w2_ZwhzB1g4\">suscríbete a AICodeKing</a> para más análisis a fondo de herramientas de IA.</em></p>",
  },
  "pt-br": {
    title: "Open Design para times — skills versionáveis, seu próprio sistema de marca e guardrails anti-slop",
    summary: "Como usar o Open Design como um fluxo de design real e versionável para um time — criar seus próprios skills e um DESIGN.md de marca, apoiar-se no portão de crítica anti-slop e manter expectativas honestas sobre o uso em produção. Baseado na análise do AICodeKing.",
    bodyHtml: "<p>Este guia é sobre usar o Open Design como um <strong>fluxo de design real e versionável</strong> — não apenas como um gerador de protótipos pontual. A combinação que o torna interessante para um time: seu agente atual, skills baseados em arquivos e sistemas de marca <code>DESIGN.md</code>, com guardrails anti-slop para impedir que o resultado pareça gerado. Ele segue a análise que o <strong>AICodeKing</strong> faz no <a href=\"https://www.youtube.com/watch?v=w2_ZwhzB1g4\">vídeo dele</a>, reescrita e atualizada para a versão atual. Assista ao vídeo acima para a explicação completa, ou continue lendo a versão escrita.</p>\n<p><img src=\"/tutorials/open-design-open-source-claude-alternative-aicodeking/plugin-library.webp\" alt=\"A biblioteca de plugins do Open Design, com skills instaláveis.\">\n<em>A biblioteca de plugins: instale skills direto do registro — incluindo skills de design anti-slop.</em></p>\n<h2 id=\"what-is-open-design\">O que é o Open Design?</h2>\n<p>O Open Design é um app de design local-first e de código aberto que se conecta ao agente de programação que você já usa. Em vez de embarcar o próprio modelo, ele detecta no seu PATH ferramentas como Claude Code, Codex, Cursor, Gemini, OpenCode e Qwen Code e usa esse agente como motor de design — com um fallback para a API da Anthropic (BYOK) se nenhum estiver instalado. É Apache-2.0, e o único custo é o do modelo que você escolher. Como diz o AICodeKing, é “uma casca de design em torno dos agentes que você já tem”.</p>\n<h2 id=\"why-its-a-team-workflow-not-just-a-chat-box\">Por que é um fluxo de time, não só uma caixa de chat</h2>\n<p>A razão pela qual o AICodeKing valoriza: não é uma caixa de prompt em branco com uma prévia. O valor está na <strong>combinação de três coisas, todas versionáveis</strong>:</p>\n<ol>\n<li><strong>Seu agente de programação atual</strong> — o motor, já pago.</li>\n<li><strong>Skills baseados em arquivos</strong> — cada skill dá ao agente regras para uma superfície específica (landing SaaS, dashboard, página de preços, docs, blog, app mobile, decks) em vez de “me faça uma página bonita”.</li>\n<li><strong>Sistemas de marca <code>DESIGN.md</code></strong> — sistemas de design em markdown puro cobrindo cor, tipografia, espaçamento, layout, componentes, movimento, tom, regras de marca e antipadrões.</li>\n</ol>\n<p>Como os skills e os sistemas de design são arquivos, um time pode <strong>criar o próprio skill interno de dashboard e o próprio <code>DESIGN.md</code> de marca, fazer commit deles no git e fazer com que o Claude Code, o Codex ou qualquer agente gere artefatos que sigam essas regras.</strong> Isso é um fluxo de design versionado, forkável e revisável — algo que uma caixa de chat de design fechada não consegue oferecer.</p>\n<p><img src=\"/tutorials/open-design-open-source-claude-alternative-aicodeking/plugins-hub.webp\" alt=\"O hub de plugins do Open Design.\">\n<em>O hub de plugins: navegue pelo registro, importe plugins e prepare-os para sua equipe.</em></p>\n<h2 id=\"the-anti-slop-machinery\">A maquinaria anti-slop</h2>\n<p>A parte favorita do AICodeKing, e a razão pela qual o resultado do time se mantém apresentável: o Open Design combate os sinais delatores de UI gerada por IA. A pilha de prompts roda uma <strong>crítica multidimensional antes de emitir um artefato</strong> (filosofia de design, hierarquia, execução, especificidade, contenção), cada skill pode vir com uma <strong>checklist P0/P1/P2</strong> que o agente precisa satisfazer, e o repositório proíbe explicitamente os modos de falha de sempre — gradientes roxos agressivos, ícones emoji genéricos, cards arredondados aleatórios com acento na borda esquerda, métricas falsas, enchimento decorativo. Combinado com o <strong>formulário de descoberta</strong> (ele pergunta sobre superfície, público, tom, marca e escala antes de escrever) e o <strong>seletor de direção</strong> (direções visuais curadas com paletas determinísticas), o agente tem uma fonte da verdade estável em vez de derivar a cada refinamento.</p>\n<h2 id=\"install\">Instalação</h2>\n<pre class=\"astro-code open-design-editorial\" style=\"background-color:#f7f1de;color:#15140f; overflow-x: auto;\" tabindex=\"0\" data-language=\"bash\"><code><span class=\"line\"><span style=\"color:#15140F;font-weight:bold\">git</span><span style=\"color:#6E7448\"> clone</span><span style=\"color:#6E7448\"> https://github.com/nexu-io/open-design.git</span></span>\n<span class=\"line\"><span style=\"color:#15140F;font-weight:bold\">cd</span><span style=\"color:#6E7448\"> open-design</span></span>\n<span class=\"line\"><span style=\"color:#15140F;font-weight:bold\">corepack</span><span style=\"color:#6E7448\"> enable</span><span style=\"color:#5A5448\"> &#x26;&#x26;</span><span style=\"color:#15140F;font-weight:bold\"> pnpm</span><span style=\"color:#6E7448\"> install</span></span>\n<span class=\"line\"><span style=\"color:#15140F;font-weight:bold\">pnpm</span><span style=\"color:#6E7448\"> tools-dev</span><span style=\"color:#6E7448\"> run</span><span style=\"color:#6E7448\"> web</span></span></code></pre>\n<p>Abra a URL local que ele imprime (uma porta dinâmica — não fixe no código). Prefere sem configuração? Pegue o <strong>app de desktop</strong> em <a href=\"https://open-design.ai/download\">open-design.ai/download</a>. No primeiro carregamento ele detecta os CLIs de agente instalados; escolha um, ou use a opção Anthropic BYOK. Navegue pela biblioteca completa de plugins em <a href=\"https://open-design.ai/plugins/\">open-design.ai/plugins</a>.</p>\n<h2 id=\"a-team-flavoured-demo\">Uma demo com cara de time</h2>\n<p>O fluxo sugerido pelo AICodeKing se encaixa direitinho no trabalho real: escolha <strong>Codex ou Claude Code</strong> como agente, escolha um <strong>skill</strong> (landing SaaS ou dashboard) e um <strong>sistema de design</strong> (por exemplo, Linear ou Stripe — fáceis de julgar). Dê um prompt concreto, como uma landing page para um produto interno, preencha o formulário de descoberta, escolha uma direção e deixe rodar. O plano chega em streaming, o agente lê o skill e o <code>DESIGN.md</code> e escreve arquivos reais.</p>\n<p><img src=\"/tutorials/open-design-open-source-claude-alternative-aicodeking/motion-gallery.webp\" alt=\"A galeria de motion e vídeo HyperFrames no Open Design.\">\n<em>A galeria HyperFrames: peças de motion e vídeo orientadas por código que você pode forkar e remixar.</em></p>\n<p>As saídas são renderizadas em uma prévia em sandbox e exportam para HTML, PDF, ZIP e Markdown (estilo PPTX para skills de deck). Como o sistema de design e o skill permanecem na pilha de prompts, os refinamentos não derivam — o agente mantém uma referência estável em vez de reinventar o visual a cada turno.</p>\n<h2 id=\"be-honest-about-production\">Seja honesto sobre produção</h2>\n<p>O AICodeKing é realista, e você também deveria ser: este é um projeto inicial, então trate-o como um forte <strong>ponto de partida</strong>, não como um time de design de produção pronto para plugar. A qualidade da saída depende muito do modelo para o qual você o aponta — um modelo fraco mais um bom sistema de design ainda dá julgamento de design fraco. O Claude Code obtém o streaming mais rico; os outros CLIs são bufferizados por linha. E como o daemon inicia agentes com um diretório de trabalho, pense bem em quais skills você instala e quais diretórios você expõe. Para protótipos rápidos, landing pages, dashboards internos e decks ele é genuinamente útil; para uma UI de produção que vai ser publicada, gere e então revise o código, teste a responsividade e refine.</p>\n<h2 id=\"tips\">Dicas</h2>\n<ul>\n<li><strong>Escreva seu próprio skill + <code>DESIGN.md</code> de marca</strong> e faça commit deles — esse é o superpoder do time.</li>\n<li><strong>Escolha um sistema de design reconhecível</strong> (Linear/Stripe) ao julgar a saída, para que a qualidade seja fácil de avaliar.</li>\n<li><strong>Apoie-se no formulário de descoberta e no seletor de direção</strong> para travar a direção antes de gerar.</li>\n<li><strong>Use um CLI local</strong> para que a geração rode sobre uma assinatura que você já paga.</li>\n<li><strong>Trate a saída como um ponto de partida</strong> para produção — revise, teste, refine.</li>\n</ul>\n<h2 id=\"faq\">Perguntas frequentes</h2>\n<p><strong>Um time pode construir seus próprios skills e sistemas de design?</strong>\nSim — skills são pastas e sistemas de design são arquivos <code>DESIGN.md</code>. Faça commit deles no git e qualquer agente conectado gera com base neles, então todo o fluxo de trabalho fica versionado e forkável.</p>\n<p><strong>O que impede a saída de parecer gerada por IA?</strong>\nUma autocrítica multidimensional antes de emitir, checklists P0/P1/P2 por skill e uma proibição explícita de padrões de slop comuns (gradientes roxos, ícones genéricos, métricas falsas), além do formulário de descoberta e do seletor de direção.</p>\n<p><strong>Está pronto para produção?</strong>\nÉ um ponto de partida inicial, porém capaz. Use-o para protótipos, dashboards, landing pages e decks; para UI de produção, revise e refine o código gerado.</p>\n<p><strong>É gratuito?</strong>\nO app é de código aberto sob Apache-2.0 e gratuito para rodar localmente. Você só paga pelo uso do modelo do agente e da chave que conectar.</p>\n<hr>\n<p><em>Este guia escrito é baseado na análise do AICodeKing. Assista ao vídeo completo acima e <a href=\"https://www.youtube.com/watch?v=w2_ZwhzB1g4\">inscreva-se no AICodeKing</a> para mais análises aprofundadas de ferramentas de IA.</em></p>",
  },
  "it": {
    title: "Open Design per i team — skill versionabili, un sistema di brand tutto tuo e guardrail anti-slop",
    summary: "Come usare Open Design come un vero flusso di design versionabile per un team — costruire le proprie skill e un DESIGN.md di brand, appoggiarsi al gate di critica anti-slop e mantenere aspettative oneste sull'uso in produzione. Basato sull'analisi di AICodeKing.",
    bodyHtml: "<p>Questa guida parla di usare Open Design come un <strong>vero flusso di design versionabile</strong> — non come un semplice generatore di prototipi una tantum. La combinazione che lo rende interessante per un team: l'agente che usi già, skill basate su file e sistemi di brand <code>DESIGN.md</code>, con guardrail anti-slop che evitano che l'output sembri generato. Segue l'analisi che <strong>AICodeKing</strong> propone nel <a href=\"https://www.youtube.com/watch?v=w2_ZwhzB1g4\">suo video</a>, riscritta e aggiornata alla release attuale. Guarda il video qui sopra per la spiegazione completa, oppure prosegui con la versione scritta.</p>\n<p><img src=\"/tutorials/open-design-open-source-claude-alternative-aicodeking/plugin-library.webp\" alt=\"La libreria di plugin di Open Design, con skill installabili.\">\n<em>La libreria di plugin: installa skill direttamente dal registro, incluse skill di design anti-slop.</em></p>\n<h2 id=\"what-is-open-design\">Che cos'è Open Design?</h2>\n<p>Open Design è un'app di design local-first e open source che si collega all'agente di coding che usi già. Invece di includere un proprio modello, rileva nel tuo PATH strumenti come Claude Code, Codex, Cursor, Gemini, OpenCode e Qwen Code e usa quell'agente come motore di design — con un ripiego sull'API di Anthropic (BYOK) se non ne è installato nessuno. È sotto licenza Apache-2.0, e l'unico costo è quello del modello che scegli. Come dice AICodeKing, è «un guscio di design attorno agli agenti che hai già».</p>\n<h2 id=\"why-its-a-team-workflow-not-just-a-chat-box\">Perché è un flusso di team, non solo una casella di chat</h2>\n<p>Il motivo per cui AICodeKing lo apprezza: non è una casella di prompt vuota con un'anteprima. Il valore sta nella <strong>combinazione di tre cose, tutte versionabili</strong>:</p>\n<ol>\n<li><strong>Il tuo agente di coding esistente</strong> — il motore, già pagato.</li>\n<li><strong>Skill basate su file</strong> — ogni skill dà all'agente regole per una superficie specifica (landing SaaS, dashboard, pagina prezzi, documentazione, blog, app mobile, presentazioni) anziché «fammi una bella pagina».</li>\n<li><strong>Sistemi di brand <code>DESIGN.md</code></strong> — sistemi di design in puro markdown che coprono colore, tipografia, spaziatura, layout, componenti, movimento, tono, regole di brand e antipattern.</li>\n</ol>\n<p>Poiché skill e sistemi di design sono file, un team può <strong>creare la propria skill interna per le dashboard e il proprio <code>DESIGN.md</code> di brand, fare il commit su git e far sì che Claude Code, Codex o qualunque agente generi artefatti che seguono quelle regole.</strong> È un flusso di design versionato, forkabile e revisionabile — qualcosa che una casella di chat di design chiusa non può offrire.</p>\n<p><img src=\"/tutorials/open-design-open-source-claude-alternative-aicodeking/plugins-hub.webp\" alt=\"L'hub dei plugin di Open Design.\">\n<em>L'hub dei plugin: esplora il registro, importa i plugin e preparali per il tuo team.</em></p>\n<h2 id=\"the-anti-slop-machinery\">Il meccanismo anti-slop</h2>\n<p>La parte preferita di AICodeKing, e il motivo per cui l'output del team resta presentabile: Open Design combatte i segnali rivelatori delle UI generate dall'IA. Lo stack di prompt esegue una <strong>critica multidimensionale prima di emettere un artefatto</strong> (filosofia di design, gerarchia, esecuzione, specificità, sobrietà), ogni skill può includere una <strong>checklist P0/P1/P2</strong> che l'agente deve soddisfare, e il repository vieta esplicitamente le solite modalità di fallimento — gradienti viola aggressivi, icone emoji generiche, card arrotondate a caso con accento sul bordo sinistro, metriche fasulle, riempitivo decorativo. Abbinato al <strong>modulo di discovery</strong> (chiede di superficie, pubblico, tono, brand e scala prima di scrivere) e al <strong>selettore di direzione</strong> (direzioni visive curate con palette deterministiche), l'agente dispone di una fonte di verità stabile invece di andare alla deriva a ogni rifinitura.</p>\n<h2 id=\"install\">Installazione</h2>\n<pre class=\"astro-code open-design-editorial\" style=\"background-color:#f7f1de;color:#15140f; overflow-x: auto;\" tabindex=\"0\" data-language=\"bash\"><code><span class=\"line\"><span style=\"color:#15140F;font-weight:bold\">git</span><span style=\"color:#6E7448\"> clone</span><span style=\"color:#6E7448\"> https://github.com/nexu-io/open-design.git</span></span>\n<span class=\"line\"><span style=\"color:#15140F;font-weight:bold\">cd</span><span style=\"color:#6E7448\"> open-design</span></span>\n<span class=\"line\"><span style=\"color:#15140F;font-weight:bold\">corepack</span><span style=\"color:#6E7448\"> enable</span><span style=\"color:#5A5448\"> &#x26;&#x26;</span><span style=\"color:#15140F;font-weight:bold\"> pnpm</span><span style=\"color:#6E7448\"> install</span></span>\n<span class=\"line\"><span style=\"color:#15140F;font-weight:bold\">pnpm</span><span style=\"color:#6E7448\"> tools-dev</span><span style=\"color:#6E7448\"> run</span><span style=\"color:#6E7448\"> web</span></span></code></pre>\n<p>Apri l'URL locale che stampa (una porta dinamica — non scriverla fissa nel codice). Preferisci senza configurazione? Scarica l'<strong>app desktop</strong> da <a href=\"https://open-design.ai/download\">open-design.ai/download</a>. Al primo avvio rileva i CLI degli agenti installati; scegline uno, oppure usa l'opzione Anthropic BYOK. Sfoglia la libreria completa di plugin su <a href=\"https://open-design.ai/plugins/\">open-design.ai/plugins</a>.</p>\n<h2 id=\"a-team-flavoured-demo\">Una demo con tono da team</h2>\n<p>Il flusso suggerito da AICodeKing si mappa pulito sul lavoro reale: scegli <strong>Codex o Claude Code</strong> come agente, una <strong>skill</strong> (landing SaaS o dashboard) e un <strong>sistema di design</strong> (per esempio Linear o Stripe — facili da giudicare). Dai un prompt concreto, come una landing page per un prodotto interno, compila il modulo di discovery, scegli una direzione e lascialo girare. Il piano arriva in streaming, l'agente legge la skill e il <code>DESIGN.md</code> e scrive file reali.</p>\n<p><img src=\"/tutorials/open-design-open-source-claude-alternative-aicodeking/motion-gallery.webp\" alt=\"La galleria di motion e video HyperFrames in Open Design.\">\n<em>La galleria HyperFrames: contenuti di motion e video guidati dal codice, da forkare e remixare.</em></p>\n<p>Gli output vengono renderizzati in un'anteprima in sandbox ed esportano in HTML, PDF, ZIP e Markdown (stile PPTX per le skill di presentazione). Poiché il sistema di design e la skill restano nello stack di prompt, le rifiniture non vanno alla deriva — l'agente mantiene un riferimento stabile invece di reinventare l'aspetto a ogni passaggio.</p>\n<h2 id=\"be-honest-about-production\">Sii onesto sulla produzione</h2>\n<p>AICodeKing ha le idee chiare, e dovresti averle anche tu: questo è un progetto in fase iniziale, quindi trattalo come un solido <strong>punto di partenza</strong>, non come un team di design di produzione pronto all'uso. La qualità dell'output dipende fortemente dal modello a cui lo punti — un modello debole più un buon sistema di design dà comunque un giudizio di design debole. Claude Code ottiene lo streaming più ricco; gli altri CLI sono bufferizzati per riga. E poiché il daemon avvia gli agenti con una directory di lavoro, rifletti bene su quali skill installi e quali directory esponi. Per prototipi rapidi, landing page, dashboard interne e presentazioni è davvero utile; per una UI di produzione da rilasciare, genera, poi rivedi il codice, testa la responsività e rifinisci.</p>\n<h2 id=\"tips\">Suggerimenti</h2>\n<ul>\n<li><strong>Scrivi la tua skill + <code>DESIGN.md</code> di brand</strong> e fanne il commit — è il superpotere del team.</li>\n<li><strong>Scegli un sistema di design riconoscibile</strong> (Linear/Stripe) quando giudichi l'output, così la qualità è facile da valutare.</li>\n<li><strong>Appoggiati al modulo di discovery e al selettore di direzione</strong> per fissare la direzione prima della generazione.</li>\n<li><strong>Usa un CLI locale</strong> così la generazione si appoggia a un abbonamento che già paghi.</li>\n<li><strong>Tratta l'output come un punto di partenza</strong> per la produzione — rivedi, testa, rifinisci.</li>\n</ul>\n<h2 id=\"faq\">FAQ</h2>\n<p><strong>Un team può costruire le proprie skill e i propri sistemi di design?</strong>\nSì — le skill sono cartelle e i sistemi di design sono file <code>DESIGN.md</code>. Fanne il commit su git e qualunque agente collegato genera basandosi su di essi, così l'intero flusso di lavoro è versionato e forkabile.</p>\n<p><strong>Cosa impedisce all'output di sembrare generato dall'IA?</strong>\nUn'autocritica multidimensionale prima dell'emissione, checklist P0/P1/P2 per ogni skill e un divieto esplicito dei pattern di slop comuni (gradienti viola, icone generiche, metriche fasulle), oltre al modulo di discovery e al selettore di direzione.</p>\n<p><strong>È pronto per la produzione?</strong>\nÈ un punto di partenza iniziale ma capace. Usalo per prototipi, dashboard, landing page e presentazioni; per la UI di produzione, rivedi e rifinisci il codice generato.</p>\n<p><strong>È gratuito?</strong>\nL'app è open source sotto Apache-2.0 e gratuita da eseguire in locale. Paghi solo l'uso del modello dell'agente e della chiave che colleghi.</p>\n<hr>\n<p><em>Questa guida scritta si basa sull'analisi di AICodeKing. Guarda il video completo qui sopra e <a href=\"https://www.youtube.com/watch?v=w2_ZwhzB1g4\">iscriviti ad AICodeKing</a> per altri approfondimenti sugli strumenti di IA.</em></p>",
  },
  "tr": {
    title: "Ekipler için Open Design — sürümlenebilir skill'ler, kendi marka sisteminiz ve anti-slop korkulukları",
    summary: "Open Design'ı bir ekip için gerçek, sürümlenebilir bir tasarım iş akışı olarak nasıl kullanırsınız — kendi skill'lerinizi ve marka DESIGN.md'nizi oluşturun, anti-slop eleştiri kapısına yaslanın ve üretim kullanımı konusunda gerçekçi beklentiler koruyun. AICodeKing'in analizine dayanmaktadır.",
    bodyHtml: "<p>Bu rehber, Open Design'ı tek seferlik bir prototip üreticisi olarak değil, <strong>gerçek, sürümlenebilir bir tasarım iş akışı</strong> olarak kullanmakla ilgilidir. Onu bir ekip için ilgi çekici kılan bileşim: zaten kullandığınız agent, dosya tabanlı skill'ler ve marka <code>DESIGN.md</code> sistemleri; çıktının üretilmiş gibi görünmesini engelleyen anti-slop korkuluklarıyla birlikte. <strong>AICodeKing</strong>'in <a href=\"https://www.youtube.com/watch?v=w2_ZwhzB1g4\">videosunda</a> sunduğu analizi izler; yeniden yazılmış ve güncel sürüme uyarlanmıştır. Tam çözümleme için yukarıdaki videoyu izleyin ya da yazılı sürüm için okumaya devam edin.</p>\n<p><img src=\"/tutorials/open-design-open-source-claude-alternative-aicodeking/plugin-library.webp\" alt=\"Kurulabilir yeteneklerle birlikte Open Design eklenti kütüphanesi.\">\n<em>Eklenti kütüphanesi: yetenekleri doğrudan kayıt defterinden kurun — anti-slop tasarım yetenekleri dahil.</em></p>\n<h2 id=\"what-is-open-design\">Open Design nedir?</h2>\n<p>Open Design, zaten kullandığınız kodlama agent'ına bağlanan, yerel öncelikli ve açık kaynaklı bir tasarım uygulamasıdır. Kendi modelini paketlemek yerine, PATH'inizden Claude Code, Codex, Cursor, Gemini, OpenCode ve Qwen Code gibi araçları algılar ve o agent'ı tasarım motoru olarak kullanır — hiçbiri kurulu değilse Anthropic API (BYOK) yedeğiyle. Lisansı Apache-2.0'dır ve tek maliyet seçtiğiniz modelin maliyetidir. AICodeKing'in deyişiyle, o «zaten sahip olduğunuz agent'ların etrafına geçirilmiş bir tasarım kabuğudur».</p>\n<h2 id=\"why-its-a-team-workflow-not-just-a-chat-box\">Neden sadece bir sohbet kutusu değil, bir ekip iş akışı</h2>\n<p>AICodeKing'in onu değerli bulma nedeni: önizlemeli boş bir komut kutusu değildir. Değer, <strong>hepsi sürümlenebilir üç şeyin bileşiminde</strong> yatar:</p>\n<ol>\n<li><strong>Mevcut kodlama agent'ınız</strong> — motor, parası zaten ödenmiş.</li>\n<li><strong>Dosya tabanlı skill'ler</strong> — her skill, agent'a «bana güzel bir sayfa yap» yerine belirli bir yüzey (SaaS açılış sayfası, dashboard, fiyatlandırma sayfası, dokümanlar, blog, mobil uygulama, desteler) için kurallar verir.</li>\n<li><strong><code>DESIGN.md</code> marka sistemleri</strong> — renk, tipografi, boşluk, yerleşim, bileşenler, hareket, ses tonu, marka kuralları ve anti-pattern'leri kapsayan, düz markdown tasarım sistemleri.</li>\n</ol>\n<p>Skill'ler ve tasarım sistemleri dosya olduğundan, bir ekip <strong>kendi iç dashboard skill'ini ve kendi marka <code>DESIGN.md</code>'sini oluşturabilir, bunları git'e commit'leyebilir ve Claude Code, Codex ya da herhangi bir agent'ın bu kurallara uyan çıktılar üretmesini sağlayabilir.</strong> Bu; sürümlenmiş, fork'lanabilir, incelenebilir bir tasarım iş akışıdır — kilitli bir tasarım sohbet kutusunun sunamayacağı bir şey.</p>\n<p><img src=\"/tutorials/open-design-open-source-claude-alternative-aicodeking/plugins-hub.webp\" alt=\"Open Design eklenti merkezi.\">\n<em>Eklenti merkezi: kayıt defterine göz atın, eklentileri içe aktarın ve ekibiniz için hazırlayın.</em></p>\n<h2 id=\"the-anti-slop-machinery\">Anti-slop mekanizması</h2>\n<p>AICodeKing'in en sevdiği bölüm ve ekip çıktısının sunulabilir kalmasının nedeni: Open Design, yapay zekâ üretimi arayüzlerin ele veren işaretleriyle savaşır. Komut yığını, bir çıktı üretmeden önce <strong>çok boyutlu bir eleştiri</strong> çalıştırır (tasarım felsefesi, hiyerarşi, uygulama, özgüllük, ölçülülük), her skill agent'ın karşılaması gereken bir <strong>P0/P1/P2 kontrol listesiyle</strong> gelebilir ve depo, alışılmış başarısızlık biçimlerini açıkça yasaklar — agresif mor gradyanlar, jenerik emoji simgeleri, sol kenar vurgulu gelişigüzel yuvarlatılmış kartlar, sahte metrikler, dekoratif dolgu. <strong>Keşif formu</strong> (yazmadan önce yüzeyi, hedef kitleyi, ses tonunu, markayı ve ölçeği sorar) ve <strong>yön seçici</strong> (deterministik paletlere sahip özenle seçilmiş görsel yönler) ile birleşince, agent her ince ayarda savrulmak yerine istikrarlı bir doğruluk kaynağına sahip olur.</p>\n<h2 id=\"install\">Kurulum</h2>\n<pre class=\"astro-code open-design-editorial\" style=\"background-color:#f7f1de;color:#15140f; overflow-x: auto;\" tabindex=\"0\" data-language=\"bash\"><code><span class=\"line\"><span style=\"color:#15140F;font-weight:bold\">git</span><span style=\"color:#6E7448\"> clone</span><span style=\"color:#6E7448\"> https://github.com/nexu-io/open-design.git</span></span>\n<span class=\"line\"><span style=\"color:#15140F;font-weight:bold\">cd</span><span style=\"color:#6E7448\"> open-design</span></span>\n<span class=\"line\"><span style=\"color:#15140F;font-weight:bold\">corepack</span><span style=\"color:#6E7448\"> enable</span><span style=\"color:#5A5448\"> &#x26;&#x26;</span><span style=\"color:#15140F;font-weight:bold\"> pnpm</span><span style=\"color:#6E7448\"> install</span></span>\n<span class=\"line\"><span style=\"color:#15140F;font-weight:bold\">pnpm</span><span style=\"color:#6E7448\"> tools-dev</span><span style=\"color:#6E7448\"> run</span><span style=\"color:#6E7448\"> web</span></span></code></pre>\n<p>Yazdırdığı yerel URL'yi açın (dinamik bir port — sabit kodlamayın). Kurulumsuz olsun mu istiyorsunuz? <strong>Masaüstü uygulamasını</strong> <a href=\"https://open-design.ai/download\">open-design.ai/download</a> adresinden edinin. İlk yüklemede kurulu agent CLI'larınızı algılar; birini seçin ya da Anthropic BYOK seçeneğini kullanın. Eklenti kütüphanesinin tamamına <a href=\"https://open-design.ai/plugins/\">open-design.ai/plugins</a> adresinden göz atın.</p>\n<h2 id=\"a-team-flavoured-demo\">Ekip tadında bir demo</h2>\n<p>AICodeKing'in önerdiği akış, gerçek işe temiz biçimde oturur: agent olarak <strong>Codex ya da Claude Code</strong>'u seçin, bir <strong>skill</strong> (SaaS açılış sayfası ya da dashboard) ve bir <strong>tasarım sistemi</strong> (örneğin Linear ya da Stripe — değerlendirmesi kolay) seçin. İç bir ürün için açılış sayfası gibi somut bir şey isteyin, keşif formunu doldurun, bir yön seçin ve çalışmasına izin verin. Plan akış halinde gelir, agent skill'i ve <code>DESIGN.md</code>'yi okur ve gerçek dosyalar yazar.</p>\n<p><img src=\"/tutorials/open-design-open-source-claude-alternative-aicodeking/motion-gallery.webp\" alt=\"Open Design'daki HyperFrames hareket ve video galerisi.\">\n<em>HyperFrames galerisi: fork'layıp yeniden düzenleyebileceğiniz, kodla yönlendirilen hareket ve video çalışmaları.</em></p>\n<p>Çıktılar bir sandbox önizlemesinde işlenir ve HTML, PDF, ZIP ve Markdown olarak dışa aktarılır (deste skill'leri için PPTX tarzı). Tasarım sistemi ve skill komut yığınında kaldığından, ince ayarlar savrulmaz — agent her turda görünümü yeniden icat etmek yerine istikrarlı bir referans korur.</p>\n<h2 id=\"be-honest-about-production\">Üretim konusunda dürüst olun</h2>\n<p>AICodeKing serinkanlı bakıyor, siz de öyle bakmalısınız: bu erken aşama bir projedir, bu yüzden onu doğrudan devreye alınabilir bir üretim tasarım ekibi değil, güçlü bir <strong>başlangıç noktası</strong> olarak görün. Çıktı kalitesi, onu yönelttiğiniz modele büyük ölçüde bağlıdır — zayıf bir model artı iyi bir tasarım sistemi yine de zayıf tasarım muhakemesi verir. Claude Code en zengin akışı alır; diğer CLI'lar satır satır tamponlanır. Ve daemon, agent'ları bir çalışma dizini ile başlattığından, hangi skill'leri kurduğunuza ve hangi dizinleri açtığınıza dikkatlice karar verin. Hızlı prototipler, açılış sayfaları, iç dashboard'lar ve desteler için gerçekten yararlıdır; yayına alınacak üretim arayüzü için önce üretin, ardından kodu inceleyin, duyarlılığı test edin ve ince ayar yapın.</p>\n<h2 id=\"tips\">İpuçları</h2>\n<ul>\n<li><strong>Kendi skill'inizi + marka <code>DESIGN.md</code>'nizi yazın</strong> ve commit'leyin — ekibin süper gücü budur.</li>\n<li>Çıktıyı değerlendirirken <strong>tanınabilir bir tasarım sistemi seçin</strong> (Linear/Stripe), böylece kaliteyi değerlendirmek kolay olur.</li>\n<li>Üretimden önce yönü sabitlemek için <strong>keşif formuna ve yön seçiciye yaslanın</strong>.</li>\n<li><strong>Yerel bir CLI kullanın</strong>, böylece üretim zaten ödediğiniz bir abonelik üzerinden gider.</li>\n<li>Üretim için <strong>çıktıyı bir başlangıç noktası olarak görün</strong> — inceleyin, test edin, ince ayar yapın.</li>\n</ul>\n<h2 id=\"faq\">SSS</h2>\n<p><strong>Bir ekip kendi skill'lerini ve tasarım sistemlerini oluşturabilir mi?</strong>\nEvet — skill'ler klasörlerdir ve tasarım sistemleri <code>DESIGN.md</code> dosyalarıdır. Bunları git'e commit'leyin; bağlı her agent onlara göre üretir, böylece tüm iş akışı sürümlenmiş ve fork'lanabilir olur.</p>\n<p><strong>Çıktının yapay zekâ üretimi gibi görünmesini ne engeller?</strong>\nÜretimden önce çok boyutlu bir öz eleştiri, skill başına P0/P1/P2 kontrol listeleri ve yaygın slop kalıplarına (mor gradyanlar, jenerik simgeler, sahte metrikler) açık bir yasak; ayrıca keşif formu ve yön seçici.</p>\n<p><strong>Üretime hazır mı?</strong>\nErken aşama ama yetkin bir başlangıç noktasıdır. Prototipler, dashboard'lar, açılış sayfaları ve desteler için kullanın; üretim arayüzü için üretilen kodu inceleyin ve ince ayar yapın.</p>\n<p><strong>Ücretsiz mi?</strong>\nUygulama Apache-2.0 altında açık kaynaktır ve yerel olarak çalıştırması ücretsizdir. Yalnızca bağladığınız agent ve anahtarın model kullanımı için ödeme yaparsınız.</p>\n<hr>\n<p><em>Bu yazılı rehber AICodeKing'in analizine dayanmaktadır. Yukarıdaki tam videoyu izleyin ve daha fazla yapay zekâ aracı derinlemesine incelemesi için <a href=\"https://www.youtube.com/watch?v=w2_ZwhzB1g4\">AICodeKing'e abone olun</a>.</em></p>",
  },
};
